    private final LauncherService launcherService;
    private final LauncherUpdateService updateService;
    private final ObjectMapper objectMapper;

    public InternalApiServer(int port, LauncherService launcherService, LauncherUpdateService updateService) {
        try {
            this.server = HttpServer.create(new InetSocketAddress(port), 0);
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo levantar la API interna", ex);
        }

        this.launcherService = launcherService;
        this.updateService = updateService;
        this.objectMapper = new ObjectMapper().findAndRegisterModules();
        this.server.setExecutor(Executors.newCachedThreadPool());
        createContexts();
    }

    public void start() {
        server.start();
    }

    public void stop() {
        launcherService.shutdown();
        server.stop(0);
    }

    public int getPort() {
        return server.getAddress().getPort();
    }

    private void createContexts() {
        server.createContext("/internal/v1/health",           exchange -> withErrorHandling(exchange, this::handleHealth));
        server.createContext("/internal/v1/profiles",         exchange -> withErrorHandling(exchange, this::handleProfiles));
        server.createContext("/internal/v1/launch",           exchange -> withErrorHandling(exchange, this::handleLaunch));
        server.createContext("/internal/v1/launch-prepared",  exchange -> withErrorHandling(exchange, this::handleLaunchPrepared));
        server.createContext("/internal/v1/launch-prepared/start", exchange -> withErrorHandling(exchange, this::handleLaunchPreparedStart));
        server.createContext("/internal/v1/downloads",        exchange -> withErrorHandling(exchange, this::handleDownloads));
        server.createContext("/internal/v1/updates/check",    exchange -> withErrorHandling(exchange, this::handleUpdateCheck));
        server.createContext("/internal/v1/versions/prepare", exchange -> withErrorHandling(exchange, this::handlePrepareVersion));
        server.createContext("/internal/v1/settings/modpack-compat", exchange -> withErrorHandling(exchange, this::handleModpackCompatibility));
    }

    private void handleHealth(HttpExchange exchange) throws IOException {
        if (!"GET".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("GET"));
            return;
        }
        sendJson(exchange, 200, launcherService.health());
    }

    private void handleProfiles(HttpExchange exchange) throws IOException {
        String path = exchange.getRequestURI().getPath();
        String method = exchange.getRequestMethod();
        String basePath = "/internal/v1/profiles";

        if ("GET".equalsIgnoreCase(method) && basePath.equals(path)) {
            sendJson(exchange, 200, launcherService.listProfiles());
            return;
        }
        if ("POST".equalsIgnoreCase(method) && basePath.equals(path)) {
            MinecraftProfile profile = readBody(exchange, MinecraftProfile.class);
            MinecraftProfile created = launcherService.createProfile(profile);
            sendJson(exchange, 201, created);
            return;
        }

        if ("GET".equalsIgnoreCase(method) && path.startsWith(basePath + "/") && path.endsWith("/instance-path")) {
            String profileId = path.substring((basePath + "/").length(), path.length() - "/instance-path".length());
            sendJson(exchange, 200, Map.of("instancePath", launcherService.getProfileInstancePath(profileId)));
            return;
        }

        if ("PUT".equalsIgnoreCase(method) && path.startsWith(basePath + "/")) {
            String existingId = path.substring((basePath + "/").length());
            MinecraftProfile profile = readBody(exchange, MinecraftProfile.class);
            MinecraftProfile updated = launcherService.updateProfile(existingId, profile);
            sendJson(exchange, 200, updated);
            return;
        }

        if ("DELETE".equalsIgnoreCase(method) && path.startsWith(basePath + "/")) {
            String profileId = path.substring((basePath + "/").length());
            MinecraftProfile deleted = launcherService.deleteProfile(profileId);
            sendJson(exchange, 200, deleted);
            return;
        }

        sendMethodNotAllowed(exchange, List.of("GET", "POST", "PUT", "DELETE"));
    }

    private void handleLaunch(HttpExchange exchange) throws IOException {
        String path   = exchange.getRequestURI().getPath();
        String method = exchange.getRequestMethod();

        // POST /internal/v1/launch  → iniciar juego
        if ("POST".equalsIgnoreCase(method) && "/internal/v1/launch".equals(path)) {
            LaunchRequest request = readBody(exchange, LaunchRequest.class);
            sendJson(exchange, 202, launcherService.launch(request));
            return;
        }

        // GET /internal/v1/launch/{id}/output?from=N  → líneas de output
        if ("GET".equalsIgnoreCase(method) && path.endsWith("/output")) {
            String id = extractSegment(path, "/output");
            int fromIndex = parseQueryInt(exchange.getRequestURI().getQuery(), "from", 0);
            sendJson(exchange, 200, launcherService.getGameOutput(id, fromIndex));
            return;
        }

        // GET /internal/v1/launch/{id}/alive  → ¿el proceso sigue vivo?
        if ("GET".equalsIgnoreCase(method) && path.endsWith("/alive")) {
            String id = extractSegment(path, "/alive");
            sendJson(exchange, 200, Map.of("alive", launcherService.isGameAlive(id)));
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private static String extractSegment(String path, String suffix) {
        String base = "/internal/v1/launch/";
        String mid  = path.substring(base.length(), path.length() - suffix.length());
        return mid;
    }

    private static int parseQueryInt(String query, String key, int defaultVal) {
        if (query == null) return defaultVal;
        for (String param : query.split("&")) {
            if (param.startsWith(key + "=")) {
                try { return Integer.parseInt(param.substring(key.length() + 1)); }
                catch (NumberFormatException ignored) {}
            }
        }
        return defaultVal;
    }

    private void handleLaunchPrepared(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        String path = exchange.getRequestURI().getPath();

        if ("POST".equalsIgnoreCase(method) && "/internal/v1/launch-prepared".equals(path)) {
            LaunchRequest request = readBody(exchange, LaunchRequest.class);
            sendJson(exchange, 202, launcherService.prepareAndLaunch(request));
            return;
        }

        if ("GET".equalsIgnoreCase(method) && path.startsWith("/internal/v1/launch-prepared/")) {
            String opId = path.substring("/internal/v1/launch-prepared/".length());
            launcherService.getPreparedLaunchStatus(opId)
                    .ifPresentOrElse(
                            status -> sendJsonUnchecked(exchange, 200, status),
                            () -> sendJsonUnchecked(exchange, 404, Map.of("error", "Operacion no encontrada"))
                    );
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private void handleLaunchPreparedStart(HttpExchange exchange) throws IOException {
        if (!"POST".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("POST"));
            return;
        }
        LaunchRequest request = readBody(exchange, LaunchRequest.class);
        sendJson(exchange, 202, launcherService.startPreparedLaunch(request));
    }

    private void handleDownloads(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        String fullPath = exchange.getRequestURI().getPath();
        String basePath = "/internal/v1/downloads";

        if ("POST".equalsIgnoreCase(method) && basePath.equals(fullPath)) {
            Map<String, String> request = readBody(exchange, new TypeReference<>() {});
            sendJson(exchange, 202, launcherService.startDownload(request.get("target")));
            return;
        }

        if ("GET".equalsIgnoreCase(method) && fullPath.startsWith(basePath + "/")) {
            String id = fullPath.substring((basePath + "/").length());
            launcherService.getDownloadStatus(id)
                    .ifPresentOrElse(
                            status -> sendJsonUnchecked(exchange, 200, status),
                            () -> sendJsonUnchecked(exchange, 404, Map.of("error", "Descarga no encontrada"))
                    );
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private void handleUpdateCheck(HttpExchange exchange) throws IOException {
        if (!"GET".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("GET"));
            return;
        }
        sendJson(exchange, 200, updateService.checkForUpdates());
    }

    private void handlePrepareVersion(HttpExchange exchange) throws IOException {
        if (!"POST".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("POST"));
            return;
        }

        Map<String, String> request = readBody(exchange, new TypeReference<>() {});
        String version = request.get("version");
        sendJson(exchange, 202, launcherService.prepareVersion(version));
    }

    private void handleModpackCompatibility(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        if ("GET".equalsIgnoreCase(method)) {
            ModpackCompatibilityMode mode = launcherService.getModpackCompatibilityMode();
            sendJson(exchange, 200, Map.of(
                    "mode", mode.name(),
                    "allowedSources", switch (mode) {
                        case BOTH -> List.of("MODRINTH", "CURSEFORGE");
                        case MODRINTH_ONLY -> List.of("MODRINTH");
                        case CURSEFORGE_ONLY -> List.of("CURSEFORGE");
                    }
            ));
            return;
        }

        if ("POST".equalsIgnoreCase(method)) {
            Map<String, String> request = readBody(exchange, new TypeReference<>() {});
            String rawMode = request.get("mode");
            ModpackCompatibilityMode mode = ModpackCompatibilityMode.fromEnvironment(rawMode);
            ModpackCompatibilityMode applied = launcherService.setModpackCompatibilityMode(mode);
            sendJson(exchange, 200, Map.of("mode", applied.name()));
            return;
        }

        sendMethodNotAllowed(exchange, List.of("GET", "POST"));
    }

    private <T> T readBody(HttpExchange exchange, Class<T> type) throws IOException {
        try (InputStream body = exchange.getRequestBody()) {
            return objectMapper.readValue(body, type);
        }
    }

    private <T> T readBody(HttpExchange exchange, TypeReference<T> typeReference) throws IOException {
        try (InputStream body = exchange.getRequestBody()) {
            return objectMapper.readValue(body, typeReference);
        }
    }

    private void withErrorHandling(HttpExchange exchange, ExchangeHandler handler) throws IOException {
        try {
            handler.handle(exchange);
        } catch (IllegalArgumentException ex) {
            sendJson(exchange, 400, Map.of("error", ex.getMessage()));
        } catch (Exception ex) {
            sendJson(exchange, 500, Map.of("error", "Error interno", "detail", ex.getMessage()));
        } finally {
            exchange.close();
        }
    }

    private void sendMethodNotAllowed(HttpExchange exchange, List<String> allowedMethods) throws IOException {
        exchange.getResponseHeaders().set("Allow", String.join(", ", allowedMethods));
        sendJson(exchange, 405, Map.of("error", "Metodo no permitido"));
    }

    private void sendJson(HttpExchange exchange, int statusCode, Object body) throws IOException {
        byte[] payload = objectMapper.writerWithDefaultPrettyPrinter().writeValueAsBytes(body);
        exchange.getResponseHeaders().set("Content-Type", "application/json; charset=utf-8");
        exchange.sendResponseHeaders(statusCode, payload.length);
        exchange.getResponseBody().write(payload);
    }

    private void sendJsonUnchecked(HttpExchange exchange, int statusCode, Object body) {
        try {
            sendJson(exchange, statusCode, body);
        } catch (IOException ex) {
            throw new IllegalStateException(ex);
        }
    }

    @FunctionalInterface
    private interface ExchangeHandler {
        void handle(HttpExchange exchange) throws IOException;
    }
}

package am.froshy.launcher.application;

import am.froshy.launcher.config.LauncherConfig;
import am.froshy.launcher.domain.DownloadStatus;
import am.froshy.launcher.domain.LaunchRequest;
import am.froshy.launcher.domain.LaunchResult;
import am.froshy.launcher.domain.MinecraftProfile;
import am.froshy.launcher.domain.ModpackManifest;
import am.froshy.launcher.domain.PreparedLaunchStatus;
import am.froshy.launcher.infrastructure.ProfileStore;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.LinkedList;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.ScheduledFuture;
import java.util.concurrent.TimeUnit;
import java.util.function.BiConsumer;

public final class LauncherService {

    private static final int MAX_OUTPUT_LINES = 2000;

    private final LauncherConfig config;
    private final ProfileStore profileStore;
    private final MinecraftVersionDownloader versionDownloader;
    private final ModpackInstaller modpackInstaller;
    private volatile ModpackCompatibilityMode modpackCompatibilityMode;

    private final Map<String, MinecraftProfile> profiles         = new ConcurrentHashMap<>();
    private final Map<String, DownloadStatus>   downloads        = new ConcurrentHashMap<>();
    private final Map<String, String>           activeVersionDls = new ConcurrentHashMap<>();
    private final Map<String, ScheduledFuture<?>> downloadTasks  = new ConcurrentHashMap<>();
    private final Map<String, PreparedLaunchStatus> preparedLaunches = new ConcurrentHashMap<>();

    // Procesos de juego activos
    private final Map<String, Process>       activeProcesses = new ConcurrentHashMap<>();
    private final Map<String, String>        activeProcessProfiles = new ConcurrentHashMap<>();
    private final Map<String, List<String>>  processOutputs  = new ConcurrentHashMap<>();

    private final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(2);

    public LauncherService(LauncherConfig config, ProfileStore profileStore) {
        this(config, profileStore, new MojangVersionDownloader(), new ModpackInstaller(),
                ModpackCompatibilityMode.fromEnvironment(System.getenv("FROSHY_MODPACK_COMPAT")));
    }

    public LauncherService(LauncherConfig config, ProfileStore profileStore,
                           MinecraftVersionDownloader versionDownloader) {
        this(config, profileStore, versionDownloader, new ModpackInstaller(),
                ModpackCompatibilityMode.fromEnvironment(System.getenv("FROSHY_MODPACK_COMPAT")));
    }

    public LauncherService(LauncherConfig config, ProfileStore profileStore,
                           MinecraftVersionDownloader versionDownloader,
                           ModpackInstaller modpackInstaller) {
        this(config, profileStore, versionDownloader, modpackInstaller,
                ModpackCompatibilityMode.fromEnvironment(System.getenv("FROSHY_MODPACK_COMPAT")));
    }

    public LauncherService(LauncherConfig config, ProfileStore profileStore,
                           MinecraftVersionDownloader versionDownloader,
                           ModpackInstaller modpackInstaller,
                           ModpackCompatibilityMode modpackCompatibilityMode) {
        this.config            = config;
        this.profileStore      = profileStore;
        this.versionDownloader = versionDownloader;
        this.modpackInstaller  = modpackInstaller;
        this.modpackCompatibilityMode = modpackCompatibilityMode == null
                ? ModpackCompatibilityMode.BOTH
                : modpackCompatibilityMode;
        profileStore.load().forEach(p -> profiles.put(p.id(), p));
    }

    // ── Perfiles ─────────────────────────────────────────────────────────

    public List<MinecraftProfile> listProfiles() {
        return new ArrayList<>(profiles.values());
    }

    public MinecraftProfile createProfile(MinecraftProfile profile) {
        if (profiles.containsKey(profile.id()))
            throw new IllegalArgumentException("Ya existe un perfil con id: " + profile.id());
        ensureProfileInstanceDirectory(profile);
        profiles.put(profile.id(), profile);
        profileStore.save(profiles.values());
        return profile;
    }

    public MinecraftProfile updateProfile(String existingId, MinecraftProfile changes) {
        if (existingId == null || existingId.isBlank()) {
            throw new IllegalArgumentException("existingId es obligatorio");
        }
        if (!profiles.containsKey(existingId)) {
            throw new IllegalArgumentException("Perfil no encontrado: " + existingId);
        }

        // En modo edicion, la ID del formulario se ignora y se conserva la original.
        MinecraftProfile updated = new MinecraftProfile(
                existingId,
                changes.displayName(),
                changes.javaPath(),
                changes.gameVersion(),
                changes.jvmArgs(),
                changes.gameArgs(),
                changes.loaderType(),
                changes.loaderVersion(),
                changes.modpackPath()
        );

        ensureProfileInstanceDirectory(updated);
        profiles.put(existingId, updated);
        profileStore.save(profiles.values());
        return updated;
    }

    public MinecraftProfile deleteProfile(String profileId) {
        if (profileId == null || profileId.isBlank()) {
            throw new IllegalArgumentException("profileId es obligatorio");
        }

        MinecraftProfile removed = profiles.remove(profileId);
        if (removed == null) {
            throw new IllegalArgumentException("Perfil no encontrado: " + profileId);
        }

        stopActiveProcessesForProfile(profileId);
        profileStore.save(profiles.values());
        deleteProfileInstanceDirectory(removed);
        return removed;
    }

    // ── Lanzamiento ───────────────────────────────────────────────────────

    public LaunchResult launch(LaunchRequest request) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(request.profileId()))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + request.profileId()));
        Path instanceDir = profileGameDirectory(profile);

        String effectiveVersion;
        try {
            effectiveVersion = resolveLaunchPlan(profile).effectiveVersionId();
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo leer el modpack del perfil: " + ex.getMessage(), ex);
        }

        return launchWithVersion(request, profile, effectiveVersion, instanceDir);
    }

    private LaunchResult launchWithVersion(LaunchRequest request, MinecraftProfile profile,
                                           String effectiveVersion, Path gameDir) {

        // Extraer username de los gameArgs del perfil (--username <valor>)
        String username = extractUsername(profile);

        // Construir instalación (classpath, mainClass, args resueltos)
        VersionInstallation install;
        try {
            install = versionDownloader.buildInstallation(
                    effectiveVersion, gameDir, username);
        } catch (IOException ex) {
            throw new IllegalStateException(
                    "Version " + effectiveVersion + " no preparada: " + ex.getMessage(), ex);
        }

        // Construir comando completo
        List<String> cmd = new ArrayList<>();
        cmd.add(profile.javaPath().isBlank() ? "java" : profile.javaPath());
        // JVM args del perfil (memoria, etc.) van ANTES de los del sistema
        cmd.addAll(profile.jvmArgs());
        // JVM args de la instalación (classpath, library.path, etc.)
        cmd.addAll(install.jvmArguments());
        // Main class
        cmd.add(install.mainClass());
        // Game arguments
        cmd.addAll(install.gameArguments());
        // Demo mode
        if (request.demoMode()) cmd.add("--demo");

        String launchId  = UUID.randomUUID().toString();
        String cmdLine   = String.join(" ", cmd);

        try {
            Files.createDirectories(gameDir);
            ProcessBuilder pb = new ProcessBuilder(cmd);
            pb.directory(gameDir.toFile());
            pb.redirectErrorStream(true);   // stderr → stdout

            Process process = pb.start();
            activeProcesses.put(launchId, process);
            activeProcessProfiles.put(launchId, profile.id());

            // Hilo lector de output
            startOutputReader(launchId, process);

            return new LaunchResult(launchId, profile.id(), cmdLine, Instant.now(), "STARTED");

        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo iniciar Minecraft: " + ex.getMessage(), ex);
        }
    }

    /** Prepara la version del perfil y la lanza en un solo flujo. */
    public LaunchResult prepareAndLaunch(LaunchRequest request) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(request.profileId()))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + request.profileId()));
        Path instanceDir = profileGameDirectory(profile);

        try {
            LaunchPlan plan = prepareProfile(profile, instanceDir, (p, m) -> {});
            return launchWithVersion(request, profile, plan.effectiveVersionId(), instanceDir);
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
            throw new IllegalStateException("No se pudo preparar el lanzamiento: " + ex.getMessage(), ex);
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo preparar el lanzamiento: " + ex.getMessage(), ex);
        }
    }

    public PreparedLaunchStatus startPreparedLaunch(LaunchRequest request) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(request.profileId()))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + request.profileId()));

        String operationId = "pl-" + UUID.randomUUID();
        PreparedLaunchStatus queued = new PreparedLaunchStatus(
                operationId,
                profile.id(),
                profile.gameVersion(),
                "QUEUED",
                0,
                "En cola..."
        );
        preparedLaunches.put(operationId, queued);

        scheduler.execute(() -> runPreparedLaunch(operationId, request, profile));
        return queued;
    }

    public Optional<PreparedLaunchStatus> getPreparedLaunchStatus(String operationId) {
        return Optional.ofNullable(preparedLaunches.get(operationId));
    }

    // ── Output del proceso ────────────────────────────────────────────────

    /** Devuelve líneas nuevas desde {@code fromIndex} y el estado del proceso. */
    public Map<String, Object> getGameOutput(String launchId, int fromIndex) {
        List<String> buffer = processOutputs.get(launchId);
        boolean alive = isGameAlive(launchId);

        if (buffer == null) {
            return Map.of("lines", List.of(), "total", 0, "alive", alive);
        }
        synchronized (buffer) {
            int total = buffer.size();
            List<String> newLines = (fromIndex < total)
                    ? List.copyOf(buffer.subList(fromIndex, total))
                    : List.of();
            return Map.of("lines", newLines, "total", total, "alive", alive);
        }
    }

    public boolean isGameAlive(String launchId) {
        Process p = activeProcesses.get(launchId);
        return p != null && p.isAlive();
    }

    private void startOutputReader(String launchId, Process process) {
        LinkedList<String> buffer = new LinkedList<>();
        processOutputs.put(launchId, buffer);

        Thread t = new Thread(() -> {
            try (BufferedReader br = new BufferedReader(
                    new InputStreamReader(process.getInputStream(), StandardCharsets.UTF_8))) {
                String line;
                while ((line = br.readLine()) != null) {
                    synchronized (buffer) {
                        buffer.add(line);
                        if (buffer.size() > MAX_OUTPUT_LINES)
                            buffer.removeFirst();
                    }
                }
            } catch (IOException ignored) {}
            // Proceso terminado
            activeProcesses.remove(launchId);
            activeProcessProfiles.remove(launchId);
        }, "game-reader-" + launchId.substring(0, 8));
        t.setDaemon(true);
        t.start();
    }

    // ── Descarga / preparación de versión ────────────────────────────────

    public DownloadStatus prepareVersion(String gameVersion) {
        if (gameVersion == null || gameVersion.isBlank())
            throw new IllegalArgumentException("version es obligatoria");

        String target = "minecraft-" + gameVersion;

        // ¿Ya instalada completamente?
        if (isVersionInstalled(gameVersion)) {
            String id = "ready-" + UUID.randomUUID();
            DownloadStatus done = new DownloadStatus(id, target, "DONE", 100);
            downloads.put(id, done);
            return done;
        }

        // ¿Ya hay una descarga activa?
        String existingId = activeVersionDls.get(gameVersion);
        if (existingId != null) {
            DownloadStatus existing = downloads.get(existingId);
            if (existing != null && !isTerminal(existing.state())) return existing;
        }

        String downloadId = "dl-" + UUID.randomUUID();
        downloads.put(downloadId, new DownloadStatus(downloadId, target, "QUEUED", 0));
        activeVersionDls.put(gameVersion, downloadId);

        scheduler.execute(() -> {
            try {
                versionDownloader.downloadVersion(gameVersion, config.gameDirectory(), (prog, msg) -> {
                    int norm = Math.max(0, Math.min(prog, 100));
                    String state = norm >= 100 ? "DONE" : "IN_PROGRESS";
                    String message = msg != null ? msg : "";
                    downloads.put(downloadId, new DownloadStatus(downloadId, target, state, norm, message));
                });
                downloads.put(downloadId, new DownloadStatus(downloadId, target, "DONE", 100, "Instalacion completada."));
            } catch (Exception ex) {
                downloads.put(downloadId, new DownloadStatus(downloadId, target, "FAILED", 0,
                        "Error: " + ex.getMessage()));
            } finally {
                activeVersionDls.remove(gameVersion, downloadId);
            }
        });

        return downloads.get(downloadId);
    }

    public Optional<DownloadStatus> getDownloadStatus(String id) {
        return Optional.ofNullable(downloads.get(id));
    }

    public DownloadStatus startDownload(String target) {
        if (target == null || target.isBlank())
            throw new IllegalArgumentException("target es obligatorio");
        String id = UUID.randomUUID().toString();
        downloads.put(id, new DownloadStatus(id, target, "QUEUED", 0));
        ScheduledFuture<?> task = scheduler.scheduleAtFixedRate(() -> {
            DownloadStatus cur = downloads.get(id);
            if (cur == null || "DONE".equals(cur.state())) return;
            int next = Math.min(100, cur.progress() + 20);
            downloads.put(id, new DownloadStatus(id, target,
                    next >= 100 ? "DONE" : "IN_PROGRESS", next));
            if (next >= 100) {
                ScheduledFuture<?> t = downloadTasks.remove(id);
                if (t != null) t.cancel(false);
            }
        }, 200, 300, TimeUnit.MILLISECONDS);
        downloadTasks.put(id, task);
        return downloads.get(id);
    }

    // ── Salud y shutdown ─────────────────────────────────────────────────

    public Map<String, Object> health() {
        return Map.of(
                "status", "UP",
                "apiPort", config.internalApiPort(),
                "profiles", profiles.size(),
                "modpackCompatibility", modpackCompatibilityMode.name(),
                "timestamp", Instant.now().toString()
        );
    }

    public ModpackCompatibilityMode getModpackCompatibilityMode() {
        return modpackCompatibilityMode;
    }

    public ModpackCompatibilityMode setModpackCompatibilityMode(ModpackCompatibilityMode mode) {
        if (mode == null) {
            throw new IllegalArgumentException("mode es obligatorio");
        }
        this.modpackCompatibilityMode = mode;
        return this.modpackCompatibilityMode;
    }

    public String getProfileInstancePath(String profileId) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(profileId))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + profileId));
        return ensureProfileInstanceDirectory(profile).toAbsolutePath().toString();
    }

    public void shutdown() {
        downloadTasks.values().forEach(t -> t.cancel(false));
        scheduler.shutdownNow();
        activeProcesses.values().forEach(Process::destroy);
    }

    // ── Utilidades ────────────────────────────────────────────────────────

    private boolean isVersionInstalled(String version) {
        Path dir  = config.gameDirectory().resolve("versions").resolve(version);
        Path jar  = dir.resolve(version + ".jar");
        Path json = dir.resolve(version + ".json");
        try {
            return Files.exists(json) && Files.exists(jar) && Files.size(jar) > 10_000;
        } catch (IOException e) { return false; }
    }

    private boolean isTerminal(String state) {
        return "DONE".equals(state) || "FAILED".equals(state);
    }

    private String extractUsername(MinecraftProfile profile) {
        List<String> args = profile.gameArgs();
        for (int i = 0; i < args.size() - 1; i++) {
            if ("--username".equals(args.get(i))) return args.get(i + 1);
        }
        // Fallback: usar el nombre del perfil sin espacios
        return profile.displayName().replaceAll("\\s+", "_");
    }

    private void runPreparedLaunch(String operationId, LaunchRequest request, MinecraftProfile profile) {
        try {
            LaunchPlan basePlan = resolveLaunchPlan(profile);
            Path instanceDir = profileGameDirectory(profile);
            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    basePlan.minecraftVersion(),
                    "PREPARING",
                    1,
                    "Verificando instalacion de Minecraft " + basePlan.minecraftVersion() + "..."
            ));

            versionDownloader.downloadVersion(basePlan.minecraftVersion(), instanceDir, (progress, message) -> {
                int mappedProgress = Math.max(1, Math.min(60, progress * 60 / 100));
                String safeMessage = (message == null || message.isBlank())
                        ? "Preparando archivos de Minecraft..."
                        : message;
                preparedLaunches.put(operationId, new PreparedLaunchStatus(
                        operationId,
                        profile.id(),
                        basePlan.minecraftVersion(),
                        "PREPARING",
                        mappedProgress,
                        safeMessage
                ));
            });

            LaunchPlan readyPlan = prepareLoadersAndModpack(operationId, profile, basePlan, instanceDir);

            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    readyPlan.effectiveVersionId(),
                    "STARTING",
                    95,
                    "Iniciando Minecraft..."
            ));

            LaunchResult result = launchWithVersion(request, profile, readyPlan.effectiveVersionId(), instanceDir);

            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    readyPlan.effectiveVersionId(),
                    "DONE",
                    100,
                    "Minecraft iniciado.",
                    result.launchId()
            ));
        } catch (Exception ex) {
            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    profile.gameVersion(),
                    "FAILED",
                    0,
                    "Error: " + ex.getMessage()
            ));
        }
    }

    private LaunchPlan prepareLoadersAndModpack(String operationId, MinecraftProfile profile,
                                                LaunchPlan basePlan, Path gameDir)
            throws IOException, InterruptedException {
        String effectiveVersion = basePlan.minecraftVersion();

        if (basePlan.hasLoader()) {
            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    basePlan.minecraftVersion(),
                    "PREPARING",
                    62,
                    "Instalando loader " + basePlan.loaderType() + " " + basePlan.loaderVersion() + "..."
            ));

            effectiveVersion = modpackInstaller.installLoader(
                    basePlan.loaderType(),
                    basePlan.minecraftVersion(),
                    basePlan.loaderVersion(),
                    gameDir,
                    (progress, message) -> preparedLaunches.put(operationId, new PreparedLaunchStatus(
                            operationId,
                            profile.id(),
                            basePlan.minecraftVersion(),
                            "PREPARING",
                            60 + Math.max(0, Math.min(progress, 100)) * 25 / 100,
                            message == null || message.isBlank() ? "Instalando loader..." : message
                    ))
            );
        }

        if (basePlan.hasModpack()) {
            Path modpackPath = basePlan.modpackPath();
            ModpackManifest manifest = parseAndValidateModpack(modpackPath);
            String launchVersion = effectiveVersion;
            modpackInstaller.installModpackFiles(modpackPath, manifest, gameDir, (progress, message) ->
                    preparedLaunches.put(operationId, new PreparedLaunchStatus(
                            operationId,
                            profile.id(),
                            launchVersion,
                            "PREPARING",
                            85 + Math.max(0, Math.min(progress, 100)) * 10 / 100,
                            message == null || message.isBlank() ? "Instalando modpack..." : message
                    ))
            );
        }

        return new LaunchPlan(
                basePlan.minecraftVersion(),
                basePlan.loaderType(),
                basePlan.loaderVersion(),
                basePlan.modpackPath(),
                effectiveVersion
        );
    }

    private LaunchPlan prepareProfile(MinecraftProfile profile, Path gameDir, BiConsumer<Integer, String> progress)
            throws IOException, InterruptedException {
        LaunchPlan plan = resolveLaunchPlan(profile);

        progress.accept(0, "Preparando Minecraft " + plan.minecraftVersion() + "...");
        versionDownloader.downloadVersion(plan.minecraftVersion(), gameDir, progress);

        String effectiveVersion = plan.minecraftVersion();
        if (plan.hasLoader()) {
            effectiveVersion = modpackInstaller.installLoader(
                    plan.loaderType(),
                    plan.minecraftVersion(),
                    plan.loaderVersion(),
                    gameDir,
                    progress
            );
        }

        if (plan.hasModpack()) {
            ModpackManifest manifest = parseAndValidateModpack(plan.modpackPath());
            modpackInstaller.installModpackFiles(plan.modpackPath(), manifest, gameDir, progress);
        }

        return new LaunchPlan(plan.minecraftVersion(), plan.loaderType(), plan.loaderVersion(), plan.modpackPath(), effectiveVersion);
    }

    private LaunchPlan resolveLaunchPlan(MinecraftProfile profile) throws IOException {
        String minecraftVersion = profile.gameVersion();
        String loaderType = profile.loaderType();
        String loaderVersion = profile.loaderVersion();
        Path modpackPath = null;

        if (profile.hasModpack()) {
            modpackPath = Path.of(profile.modpackPath());
            if (!Files.exists(modpackPath)) {
                throw new IOException("No existe el modpack en ruta: " + modpackPath);
            }

            ModpackManifest manifest = parseAndValidateModpack(modpackPath);
            if (manifest.minecraftVersion() != null && !manifest.minecraftVersion().isBlank()) {
                minecraftVersion = manifest.minecraftVersion();
            }
            if (manifest.loaderType() != null && !manifest.loaderType().isBlank()) {
                loaderType = manifest.loaderType();
            }
            if (manifest.loaderVersion() != null && !manifest.loaderVersion().isBlank()) {
                loaderVersion = manifest.loaderVersion();
            }
        }

        String effectiveVersion = ModpackInstaller.computeEffectiveVersionId(
                minecraftVersion,
                loaderType,
                loaderVersion
        );

        return new LaunchPlan(minecraftVersion, loaderType, loaderVersion, modpackPath, effectiveVersion);
    }

    private ModpackManifest parseAndValidateModpack(Path modpackPath) throws IOException {
        ModpackManifest manifest = modpackInstaller.parseModpack(modpackPath);
        if (!modpackCompatibilityMode.isAllowed(manifest.source())) {
            throw new IOException("Formato de modpack no permitido por compatibilidad actual ("
                    + modpackCompatibilityMode + "): " + manifest.source());
        }
        return manifest;
    }

    private Path profileGameDirectory(MinecraftProfile profile) {
        String safeId = profile.id().replaceAll("[^a-zA-Z0-9._-]", "_");
        return config.gameDirectory().resolve("instances").resolve(safeId);
    }

    private Path ensureProfileInstanceDirectory(MinecraftProfile profile) {
        Path instanceDir = profileGameDirectory(profile);
        try {
            Files.createDirectories(instanceDir);
            return instanceDir;
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo preparar la instancia del perfil " + profile.id(), ex);
        }
    }

    private void deleteProfileInstanceDirectory(MinecraftProfile profile) {
        Path instanceDir = profileGameDirectory(profile);
        if (!Files.exists(instanceDir)) {
            return;
        }
        try (java.util.stream.Stream<Path> walk = Files.walk(instanceDir)) {
            walk.sorted(Comparator.reverseOrder()).forEach(path -> {
                try {
                    Files.deleteIfExists(path);
                } catch (IOException ex) {
                    throw new IllegalStateException("No se pudo eliminar la instancia del perfil " + profile.id(), ex);
                }
            });
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo eliminar la instancia del perfil " + profile.id(), ex);
        }
    }

    private void stopActiveProcessesForProfile(String profileId) {
        activeProcessProfiles.entrySet().stream()
                .filter(entry -> profileId.equals(entry.getValue()))
                .map(Map.Entry::getKey)
                .forEach(this::stopProcessByLaunchId);
    }

    private void stopProcessByLaunchId(String launchId) {
        Process process = activeProcesses.get(launchId);
        if (process == null) {
            activeProcessProfiles.remove(launchId);
            return;
        }

        try {
            process.destroy();
            if (!process.waitFor(2, TimeUnit.SECONDS)) {
                process.destroyForcibly();
                process.waitFor(2, TimeUnit.SECONDS);
            }
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
        } finally {
            activeProcesses.remove(launchId);
            activeProcessProfiles.remove(launchId);
        }
    }

    private record LaunchPlan(
            String minecraftVersion,
            String loaderType,
            String loaderVersion,
            Path modpackPath,
            String effectiveVersionId
    ) {
        private boolean hasLoader() {
            return loaderType != null && !loaderType.isBlank() && !"VANILLA".equalsIgnoreCase(loaderType);
        }

        private boolean hasModpack() {
            return modpackPath != null;
        }
    }
}

package am.froshy.launcher.application;

import am.froshy.launcher.config.LauncherConfig;
import am.froshy.launcher.domain.DownloadStatus;
import am.froshy.launcher.domain.LaunchRequest;
import am.froshy.launcher.domain.LaunchResult;
import am.froshy.launcher.domain.MinecraftProfile;
import am.froshy.launcher.domain.ModpackManifest;
import am.froshy.launcher.domain.PreparedLaunchStatus;
import am.froshy.launcher.infrastructure.ProfileStore;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.LinkedList;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.ScheduledFuture;
import java.util.concurrent.TimeUnit;
import java.util.function.BiConsumer;

public final class LauncherService {

    private static final int MAX_OUTPUT_LINES = 2000;

    private final LauncherConfig config;
    private final ProfileStore profileStore;
    private final MinecraftVersionDownloader versionDownloader;
    private final ModpackInstaller modpackInstaller;
    private volatile ModpackCompatibilityMode modpackCompatibilityMode;

    private final Map<String, MinecraftProfile> profiles         = new ConcurrentHashMap<>();
    private final Map<String, DownloadStatus>   downloads        = new ConcurrentHashMap<>();
    private final Map<String, String>           activeVersionDls = new ConcurrentHashMap<>();
    private final Map<String, ScheduledFuture<?>> downloadTasks  = new ConcurrentHashMap<>();
    private final Map<String, PreparedLaunchStatus> preparedLaunches = new ConcurrentHashMap<>();

    // Procesos de juego activos
    private final Map<String, Process>       activeProcesses = new ConcurrentHashMap<>();
    private final Map<String, String>        activeProcessProfiles = new ConcurrentHashMap<>();
    private final Map<String, List<String>>  processOutputs  = new ConcurrentHashMap<>();

    private final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(2);

    public LauncherService(LauncherConfig config, ProfileStore profileStore) {
        this(config, profileStore, new MojangVersionDownloader(), new ModpackInstaller(),
                ModpackCompatibilityMode.fromEnvironment(System.getenv("FROSHY_MODPACK_COMPAT")));
    }

    public LauncherService(LauncherConfig config, ProfileStore profileStore,
                           MinecraftVersionDownloader versionDownloader) {
        this(config, profileStore, versionDownloader, new ModpackInstaller(),
                ModpackCompatibilityMode.fromEnvironment(System.getenv("FROSHY_MODPACK_COMPAT")));
    }

    public LauncherService(LauncherConfig config, ProfileStore profileStore,
                           MinecraftVersionDownloader versionDownloader,
                           ModpackInstaller modpackInstaller) {
        this(config, profileStore, versionDownloader, modpackInstaller,
                ModpackCompatibilityMode.fromEnvironment(System.getenv("FROSHY_MODPACK_COMPAT")));
    }

    public LauncherService(LauncherConfig config, ProfileStore profileStore,
                           MinecraftVersionDownloader versionDownloader,
                           ModpackInstaller modpackInstaller,
                           ModpackCompatibilityMode modpackCompatibilityMode) {
        this.config            = config;
        this.profileStore      = profileStore;
        this.versionDownloader = versionDownloader;
        this.modpackInstaller  = modpackInstaller;
        this.modpackCompatibilityMode = modpackCompatibilityMode == null
                ? ModpackCompatibilityMode.BOTH
                : modpackCompatibilityMode;
        profileStore.load().forEach(p -> profiles.put(p.id(), p));
    }

    // ── Perfiles ─────────────────────────────────────────────────────────

    public List<MinecraftProfile> listProfiles() {
        return new ArrayList<>(profiles.values());
    }

    public MinecraftProfile createProfile(MinecraftProfile profile) {
        if (profiles.containsKey(profile.id()))
            throw new IllegalArgumentException("Ya existe un perfil con id: " + profile.id());
        ensureProfileInstanceDirectory(profile);
        profiles.put(profile.id(), profile);
        profileStore.save(profiles.values());
        return profile;
    }

    public MinecraftProfile updateProfile(String existingId, MinecraftProfile changes) {
        if (existingId == null || existingId.isBlank()) {
            throw new IllegalArgumentException("existingId es obligatorio");
        }
        if (!profiles.containsKey(existingId)) {
            throw new IllegalArgumentException("Perfil no encontrado: " + existingId);
        }

        // En modo edicion, la ID del formulario se ignora y se conserva la original.
        MinecraftProfile updated = new MinecraftProfile(
                existingId,
                changes.displayName(),
                changes.javaPath(),
                changes.gameVersion(),
                changes.jvmArgs(),
                changes.gameArgs(),
                changes.loaderType(),
                changes.loaderVersion(),
                changes.modpackPath()
        );

        ensureProfileInstanceDirectory(updated);
        profiles.put(existingId, updated);
        profileStore.save(profiles.values());
        return updated;
    }

    public MinecraftProfile deleteProfile(String profileId) {
        if (profileId == null || profileId.isBlank()) {
            throw new IllegalArgumentException("profileId es obligatorio");
        }

        MinecraftProfile removed = profiles.remove(profileId);
        if (removed == null) {
            throw new IllegalArgumentException("Perfil no encontrado: " + profileId);
        }

        stopActiveProcessesForProfile(profileId);
        profileStore.save(profiles.values());
        deleteProfileInstanceDirectory(removed);
        return removed;
    }

    // ── Lanzamiento ───────────────────────────────────────────────────────

    public LaunchResult launch(LaunchRequest request) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(request.profileId()))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + request.profileId()));
        Path instanceDir = profileGameDirectory(profile);

        String effectiveVersion;
        try {
            effectiveVersion = resolveLaunchPlan(profile).effectiveVersionId();
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo leer el modpack del perfil: " + ex.getMessage(), ex);
        }

        return launchWithVersion(request, profile, effectiveVersion, instanceDir);
    }

    private LaunchResult launchWithVersion(LaunchRequest request, MinecraftProfile profile,
                                           String effectiveVersion, Path gameDir) {

        // Extraer username de los gameArgs del perfil (--username <valor>)
        String username = extractUsername(profile);

        // Construir instalación (classpath, mainClass, args resueltos)
        VersionInstallation install;
        try {
            install = versionDownloader.buildInstallation(
                    effectiveVersion, gameDir, username);
        } catch (IOException ex) {
            throw new IllegalStateException(
                    "Version " + effectiveVersion + " no preparada: " + ex.getMessage(), ex);
        }

        // Construir comando completo
        List<String> cmd = new ArrayList<>();
        cmd.add(profile.javaPath().isBlank() ? "java" : profile.javaPath());
        // JVM args del perfil (memoria, etc.) van ANTES de los del sistema
        cmd.addAll(profile.jvmArgs());
        // JVM args de la instalación (classpath, library.path, etc.)
        cmd.addAll(install.jvmArguments());
        // Main class
        cmd.add(install.mainClass());
        // Game arguments
        cmd.addAll(install.gameArguments());
        // Demo mode
        if (request.demoMode()) cmd.add("--demo");

        String launchId  = UUID.randomUUID().toString();
        String cmdLine   = String.join(" ", cmd);

        try {
            Files.createDirectories(gameDir);
            ProcessBuilder pb = new ProcessBuilder(cmd);
            pb.directory(gameDir.toFile());
            pb.redirectErrorStream(true);   // stderr → stdout

            Process process = pb.start();
            activeProcesses.put(launchId, process);
            activeProcessProfiles.put(launchId, profile.id());

            // Hilo lector de output
            startOutputReader(launchId, process);

            return new LaunchResult(launchId, profile.id(), cmdLine, Instant.now(), "STARTED");

        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo iniciar Minecraft: " + ex.getMessage(), ex);
        }
    }

    /** Prepara la version del perfil y la lanza en un solo flujo. */
    public LaunchResult prepareAndLaunch(LaunchRequest request) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(request.profileId()))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + request.profileId()));
        Path instanceDir = profileGameDirectory(profile);

        try {
            LaunchPlan plan = prepareProfile(profile, instanceDir, (p, m) -> {});
            return launchWithVersion(request, profile, plan.effectiveVersionId(), instanceDir);
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
            throw new IllegalStateException("No se pudo preparar el lanzamiento: " + ex.getMessage(), ex);
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo preparar el lanzamiento: " + ex.getMessage(), ex);
        }
    }

    public PreparedLaunchStatus startPreparedLaunch(LaunchRequest request) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(request.profileId()))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + request.profileId()));

        String operationId = "pl-" + UUID.randomUUID();
        PreparedLaunchStatus queued = new PreparedLaunchStatus(
                operationId,
                profile.id(),
                profile.gameVersion(),
                "QUEUED",
                0,
                "En cola..."
        );
        preparedLaunches.put(operationId, queued);

        scheduler.execute(() -> runPreparedLaunch(operationId, request, profile));
        return queued;
    }

    public Optional<PreparedLaunchStatus> getPreparedLaunchStatus(String operationId) {
        return Optional.ofNullable(preparedLaunches.get(operationId));
    }

    // ── Output del proceso ────────────────────────────────────────────────

    /** Devuelve líneas nuevas desde {@code fromIndex} y el estado del proceso. */
    public Map<String, Object> getGameOutput(String launchId, int fromIndex) {
        List<String> buffer = processOutputs.get(launchId);
        boolean alive = isGameAlive(launchId);

        if (buffer == null) {
            return Map.of("lines", List.of(), "total", 0, "alive", alive);
        }
        synchronized (buffer) {
            int total = buffer.size();
            List<String> newLines = (fromIndex < total)
                    ? List.copyOf(buffer.subList(fromIndex, total))
                    : List.of();
            return Map.of("lines", newLines, "total", total, "alive", alive);
        }
    }

    public boolean isGameAlive(String launchId) {
        Process p = activeProcesses.get(launchId);
        return p != null && p.isAlive();
    }

    private void startOutputReader(String launchId, Process process) {
        LinkedList<String> buffer = new LinkedList<>();
        processOutputs.put(launchId, buffer);

        Thread t = new Thread(() -> {
            try (BufferedReader br = new BufferedReader(
                    new InputStreamReader(process.getInputStream(), StandardCharsets.UTF_8))) {
                String line;
                while ((line = br.readLine()) != null) {
                    synchronized (buffer) {
                        buffer.add(line);
                        if (buffer.size() > MAX_OUTPUT_LINES)
                            buffer.removeFirst();
                    }
                }
            } catch (IOException ignored) {}
            // Proceso terminado
            activeProcesses.remove(launchId);
            activeProcessProfiles.remove(launchId);
        }, "game-reader-" + launchId.substring(0, 8));
        t.setDaemon(true);
        t.start();
    }

    // ── Descarga / preparación de versión ────────────────────────────────

    public DownloadStatus prepareVersion(String gameVersion) {
        if (gameVersion == null || gameVersion.isBlank())
            throw new IllegalArgumentException("version es obligatoria");

        String target = "minecraft-" + gameVersion;

        // ¿Ya instalada completamente?
        if (isVersionInstalled(gameVersion)) {
            String id = "ready-" + UUID.randomUUID();
            DownloadStatus done = new DownloadStatus(id, target, "DONE", 100);
            downloads.put(id, done);
            return done;
        }

        // ¿Ya hay una descarga activa?
        String existingId = activeVersionDls.get(gameVersion);
        if (existingId != null) {
            DownloadStatus existing = downloads.get(existingId);
            if (existing != null && !isTerminal(existing.state())) return existing;
        }

        String downloadId = "dl-" + UUID.randomUUID();
        downloads.put(downloadId, new DownloadStatus(downloadId, target, "QUEUED", 0));
        activeVersionDls.put(gameVersion, downloadId);

        scheduler.execute(() -> {
            try {
                versionDownloader.downloadVersion(gameVersion, config.gameDirectory(), (prog, msg) -> {
                    int norm = Math.max(0, Math.min(prog, 100));
                    String state = norm >= 100 ? "DONE" : "IN_PROGRESS";
                    String message = msg != null ? msg : "";
                    downloads.put(downloadId, new DownloadStatus(downloadId, target, state, norm, message));
                });
                downloads.put(downloadId, new DownloadStatus(downloadId, target, "DONE", 100, "Instalacion completada."));
            } catch (Exception ex) {
                downloads.put(downloadId, new DownloadStatus(downloadId, target, "FAILED", 0,
                        "Error: " + ex.getMessage()));
            } finally {
                activeVersionDls.remove(gameVersion, downloadId);
            }
        });

        return downloads.get(downloadId);
    }

    public Optional<DownloadStatus> getDownloadStatus(String id) {
        return Optional.ofNullable(downloads.get(id));
    }

    public DownloadStatus startDownload(String target) {
        if (target == null || target.isBlank())
            throw new IllegalArgumentException("target es obligatorio");
        String id = UUID.randomUUID().toString();
        downloads.put(id, new DownloadStatus(id, target, "QUEUED", 0));
        ScheduledFuture<?> task = scheduler.scheduleAtFixedRate(() -> {
            DownloadStatus cur = downloads.get(id);
            if (cur == null || "DONE".equals(cur.state())) return;
            int next = Math.min(100, cur.progress() + 20);
            downloads.put(id, new DownloadStatus(id, target,
                    next >= 100 ? "DONE" : "IN_PROGRESS", next));
            if (next >= 100) {
                ScheduledFuture<?> t = downloadTasks.remove(id);
                if (t != null) t.cancel(false);
            }
        }, 200, 300, TimeUnit.MILLISECONDS);
        downloadTasks.put(id, task);
        return downloads.get(id);
    }

    // ── Salud y shutdown ─────────────────────────────────────────────────

    public Map<String, Object> health() {
        return Map.of(
                "status", "UP",
                "apiPort", config.internalApiPort(),
                "profiles", profiles.size(),
                "modpackCompatibility", modpackCompatibilityMode.name(),
                "timestamp", Instant.now().toString()
        );
    }

    public ModpackCompatibilityMode getModpackCompatibilityMode() {
        return modpackCompatibilityMode;
    }

    public ModpackCompatibilityMode setModpackCompatibilityMode(ModpackCompatibilityMode mode) {
        if (mode == null) {
            throw new IllegalArgumentException("mode es obligatorio");
        }
        this.modpackCompatibilityMode = mode;
        return this.modpackCompatibilityMode;
    }

    public String getProfileInstancePath(String profileId) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(profileId))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + profileId));
        return ensureProfileInstanceDirectory(profile).toAbsolutePath().toString();
    }

    public void shutdown() {
        downloadTasks.values().forEach(t -> t.cancel(false));
        scheduler.shutdownNow();
        activeProcesses.values().forEach(Process::destroy);
    }

    // ── Utilidades ────────────────────────────────────────────────────────

    private boolean isVersionInstalled(String version) {
        Path dir  = config.gameDirectory().resolve("versions").resolve(version);
        Path jar  = dir.resolve(version + ".jar");
        Path json = dir.resolve(version + ".json");
        try {
            return Files.exists(json) && Files.exists(jar) && Files.size(jar) > 10_000;
        } catch (IOException e) { return false; }
    }

    private boolean isTerminal(String state) {
        return "DONE".equals(state) || "FAILED".equals(state);
    }

    private String extractUsername(MinecraftProfile profile) {
        List<String> args = profile.gameArgs();
        for (int i = 0; i < args.size() - 1; i++) {
            if ("--username".equals(args.get(i))) {
                String candidate = args.get(i + 1);
                if (candidate != null && candidate.matches("^[A-Za-z0-9_]{3,16}$")) {
                    return candidate;
                }
            }
        }
        // Fallback: usar el nombre del perfil sin espacios
        String fallback = profile.displayName().replaceAll("[^A-Za-z0-9_]", "_");
        if (fallback.length() < 3) fallback = "Steve";
        if (fallback.length() > 16) fallback = fallback.substring(0, 16);
        return fallback;
    }

    private void runPreparedLaunch(String operationId, LaunchRequest request, MinecraftProfile profile) {
        try {
            LaunchPlan basePlan = resolveLaunchPlan(profile);
            Path instanceDir = profileGameDirectory(profile);
            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    basePlan.minecraftVersion(),
                    "PREPARING",
                    1,
                    "Verificando instalacion de Minecraft " + basePlan.minecraftVersion() + "..."
            ));

            versionDownloader.downloadVersion(basePlan.minecraftVersion(), instanceDir, (progress, message) -> {
                int mappedProgress = Math.max(1, Math.min(60, progress * 60 / 100));
                String safeMessage = (message == null || message.isBlank())
                        ? "Preparando archivos de Minecraft..."
                        : message;
                preparedLaunches.put(operationId, new PreparedLaunchStatus(
                        operationId,
                        profile.id(),
                        basePlan.minecraftVersion(),
                        "PREPARING",
                        mappedProgress,
                        safeMessage
                ));
            });

            LaunchPlan readyPlan = prepareLoadersAndModpack(operationId, profile, basePlan, instanceDir);

            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    readyPlan.effectiveVersionId(),
                    "STARTING",
                    95,
                    "Iniciando Minecraft..."
            ));

            LaunchResult result = launchWithVersion(request, profile, readyPlan.effectiveVersionId(), instanceDir);

            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    readyPlan.effectiveVersionId(),
                    "DONE",
                    100,
                    "Minecraft iniciado.",
                    result.launchId()
            ));
        } catch (Exception ex) {
            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    profile.gameVersion(),
                    "FAILED",
                    0,
                    "Error: " + ex.getMessage()
            ));
        }
    }

    private LaunchPlan prepareLoadersAndModpack(String operationId, MinecraftProfile profile,
                                                LaunchPlan basePlan, Path gameDir)
            throws IOException, InterruptedException {
        String effectiveVersion = basePlan.minecraftVersion();

        if (basePlan.hasLoader()) {
            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    basePlan.minecraftVersion(),
                    "PREPARING",
                    62,
                    "Instalando loader " + basePlan.loaderType() + " " + basePlan.loaderVersion() + "..."
            ));

            effectiveVersion = modpackInstaller.installLoader(
                    basePlan.loaderType(),
                    basePlan.minecraftVersion(),
                    basePlan.loaderVersion(),
                    gameDir,
                    (progress, message) -> preparedLaunches.put(operationId, new PreparedLaunchStatus(
                            operationId,
                            profile.id(),
                            basePlan.minecraftVersion(),
                            "PREPARING",
                            60 + Math.max(0, Math.min(progress, 100)) * 25 / 100,
                            message == null || message.isBlank() ? "Instalando loader..." : message
                    ))
            );
        }

        if (basePlan.hasModpack()) {
            Path modpackPath = basePlan.modpackPath();
            ModpackManifest manifest = parseAndValidateModpack(modpackPath);
            String launchVersion = effectiveVersion;
            modpackInstaller.installModpackFiles(modpackPath, manifest, gameDir, (progress, message) ->
                    preparedLaunches.put(operationId, new PreparedLaunchStatus(
                            operationId,
                            profile.id(),
                            launchVersion,
                            "PREPARING",
                            85 + Math.max(0, Math.min(progress, 100)) * 10 / 100,
                            message == null || message.isBlank() ? "Instalando modpack..." : message
                    ))
            );
        }

        return new LaunchPlan(
                basePlan.minecraftVersion(),
                basePlan.loaderType(),
                basePlan.loaderVersion(),
                basePlan.modpackPath(),
                effectiveVersion
        );
    }

    private LaunchPlan prepareProfile(MinecraftProfile profile, Path gameDir, BiConsumer<Integer, String> progress)
            throws IOException, InterruptedException {
        LaunchPlan plan = resolveLaunchPlan(profile);

        progress.accept(0, "Preparando Minecraft " + plan.minecraftVersion() + "...");
        versionDownloader.downloadVersion(plan.minecraftVersion(), gameDir, progress);

        String effectiveVersion = plan.minecraftVersion();
        if (plan.hasLoader()) {
            effectiveVersion = modpackInstaller.installLoader(
                    plan.loaderType(),
                    plan.minecraftVersion(),
                    plan.loaderVersion(),
                    gameDir,
                    progress
            );
        }

        if (plan.hasModpack()) {
            ModpackManifest manifest = parseAndValidateModpack(plan.modpackPath());
            modpackInstaller.installModpackFiles(plan.modpackPath(), manifest, gameDir, progress);
        }

        return new LaunchPlan(plan.minecraftVersion(), plan.loaderType(), plan.loaderVersion(), plan.modpackPath(), effectiveVersion);
    }

    private LaunchPlan resolveLaunchPlan(MinecraftProfile profile) throws IOException {
        String minecraftVersion = profile.gameVersion();
        String loaderType = profile.loaderType();
        String loaderVersion = profile.loaderVersion();
        Path modpackPath = null;

        if (profile.hasModpack()) {
            modpackPath = Path.of(profile.modpackPath());
            if (!Files.exists(modpackPath)) {
                throw new IOException("No existe el modpack en ruta: " + modpackPath);
            }

            ModpackManifest manifest = parseAndValidateModpack(modpackPath);
            if (manifest.minecraftVersion() != null && !manifest.minecraftVersion().isBlank()) {
                minecraftVersion = manifest.minecraftVersion();
            }
            if (manifest.loaderType() != null && !manifest.loaderType().isBlank()) {
                loaderType = manifest.loaderType();
            }
            if (manifest.loaderVersion() != null && !manifest.loaderVersion().isBlank()) {
                loaderVersion = manifest.loaderVersion();
            }
        }

        String effectiveVersion = ModpackInstaller.computeEffectiveVersionId(
                minecraftVersion,
                loaderType,
                loaderVersion
        );

        return new LaunchPlan(minecraftVersion, loaderType, loaderVersion, modpackPath, effectiveVersion);
    }

    private ModpackManifest parseAndValidateModpack(Path modpackPath) throws IOException {
        ModpackManifest manifest = modpackInstaller.parseModpack(modpackPath);
        if (!modpackCompatibilityMode.isAllowed(manifest.source())) {
            throw new IOException("Formato de modpack no permitido por compatibilidad actual ("
                    + modpackCompatibilityMode + "): " + manifest.source());
        }
        return manifest;
    }

    private Path profileGameDirectory(MinecraftProfile profile) {
        String safeId = profile.id().replaceAll("[^a-zA-Z0-9._-]", "_");
        return config.gameDirectory().resolve("instances").resolve(safeId);
    }

    private Path ensureProfileInstanceDirectory(MinecraftProfile profile) {
        Path instanceDir = profileGameDirectory(profile);
        try {
            Files.createDirectories(instanceDir);
            return instanceDir;
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo preparar la instancia del perfil " + profile.id(), ex);
        }
    }

    private void deleteProfileInstanceDirectory(MinecraftProfile profile) {
        Path instanceDir = profileGameDirectory(profile);
        if (!Files.exists(instanceDir)) {
            return;
        }
        try (java.util.stream.Stream<Path> walk = Files.walk(instanceDir)) {
            walk.sorted(Comparator.reverseOrder()).forEach(path -> {
                try {
                    Files.deleteIfExists(path);
                } catch (IOException ex) {
                    throw new IllegalStateException("No se pudo eliminar la instancia del perfil " + profile.id(), ex);
                }
            });
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo eliminar la instancia del perfil " + profile.id(), ex);
        }
    }

    private void stopActiveProcessesForProfile(String profileId) {
        activeProcessProfiles.entrySet().stream()
                .filter(entry -> profileId.equals(entry.getValue()))
                .map(Map.Entry::getKey)
                .forEach(this::stopProcessByLaunchId);
    }

    private void stopProcessByLaunchId(String launchId) {
        Process process = activeProcesses.get(launchId);
        if (process == null) {
            activeProcessProfiles.remove(launchId);
            return;
        }

        try {
            process.destroy();
            if (!process.waitFor(2, TimeUnit.SECONDS)) {
                process.destroyForcibly();
                process.waitFor(2, TimeUnit.SECONDS);
            }
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
        } finally {
            activeProcesses.remove(launchId);
            activeProcessProfiles.remove(launchId);
        }
    }

    private record LaunchPlan(
            String minecraftVersion,
            String loaderType,
            String loaderVersion,
            Path modpackPath,
            String effectiveVersionId
    ) {
        private boolean hasLoader() {
            return loaderType != null && !loaderType.isBlank() && !"VANILLA".equalsIgnoreCase(loaderType);
        }

        private boolean hasModpack() {
            return modpackPath != null;
        }
    }
}

package am.froshy.launcher.application;

import am.froshy.launcher.domain.ModpackFile;
import am.froshy.launcher.domain.ModpackManifest;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.io.BufferedReader;
import java.io.File;
import java.io.IOException;
import java.io.InputStreamReader;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.StandardCopyOption;
import java.nio.file.StandardOpenOption;
import java.time.Duration;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Set;
import java.util.concurrent.CompletionService;
import java.util.concurrent.ExecutionException;
import java.util.concurrent.ExecutorCompletionService;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.function.BiConsumer;
import java.util.zip.ZipEntry;
import java.util.zip.ZipInputStream;

/**
 * Parsea e instala modpacks en formato Modrinth (.mrpack) y CurseForge (.zip),
 * e instala automáticamente los loaders Forge / NeoForge / Fabric / Quilt.
 */
public final class ModpackInstaller {

    private static final String CURSE_API  = "https://api.curse.tools/v1/cf";
    private static final int    MOD_THREADS = 8;
    private static final int    MAX_RETRIES = 3;
    private static final String MODPACK_STATE_FILE = ".froshy-modpack-state.json";
    private static final List<String> LEGACY_MANAGED_PATHS = List.of(
            "mods",
            "resourcepacks",
            "texturepacks",
            "shaderpacks",
            "config",
            "defaultconfigs",
            "kubejs",
            "datapacks",
            "patchouli_books",
            "options.txt",
            "optionsof.txt",
            "optionsshaders.txt",
            "servers.dat"
    );
    private static final Set<String> CLIENT_CONTENT_ROOTS = Set.of(
            "mods",
            "config",
            "defaultconfigs",
            "resourcepacks",
            "texturepacks",
            "shaderpacks",
            "kubejs",
            "datapacks",
            "patchouli_books",
            "options.txt",
            "optionsof.txt",
            "optionsshaders.txt",
            "servers.dat"
    );

    private final HttpClient   http;
    private final ObjectMapper mapper;

    public ModpackInstaller() {
        this.http = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(20))
                .followRedirects(HttpClient.Redirect.ALWAYS)
                .build();
        this.mapper = new ObjectMapper();
    }

    // ══════════════════════════════════════════════════════════════════════
    //  PARSEO
    // ══════════════════════════════════════════════════════════════════════

    /**
     * Parsea un modpack (.mrpack o .zip con manifest.json CurseForge).
     * No descarga nada; sólo devuelve los metadatos y la lista de archivos.
     */
    public ModpackManifest parseModpack(Path zipFile) throws IOException {
        try (ZipInputStream zip = new ZipInputStream(Files.newInputStream(zipFile))) {
            ZipEntry entry;
            while ((entry = zip.getNextEntry()) != null) {
                String name = normalizeZipEntryName(entry.getName());
                if (isEntryNamed(name, "modrinth.index.json")) {
                    return parseModrinth(mapper.readTree(zip.readAllBytes()));
                }
                if (isEntryNamed(name, "manifest.json")) {
                    return parseCurseForge(mapper.readTree(zip.readAllBytes()));
                }
                zip.closeEntry();
            }
        }
        throw new IOException("Formato de modpack no reconocido. " +
                "Se esperaba modrinth.index.json (Modrinth) o manifest.json (CurseForge).");
    }

    private ModpackManifest parseModrinth(JsonNode root) {
        String name        = root.path("name").asText("Modpack");
        String packVersion = root.path("versionId").asText("1.0.0");
        JsonNode deps      = root.path("dependencies");
        String mcVersion   = deps.path("minecraft").asText("1.20.1");

        String loaderType    = "VANILLA";
        String loaderVersion = "";
        if (deps.has("fabric-loader")) { loaderType = "FABRIC";   loaderVersion = deps.path("fabric-loader").asText(); }
        else if (deps.has("forge"))    { loaderType = "FORGE";    loaderVersion = deps.path("forge").asText(); }
        else if (deps.has("neoforge")) { loaderType = "NEOFORGE"; loaderVersion = deps.path("neoforge").asText(); }
        else if (deps.has("quilt-loader")) { loaderType = "QUILT"; loaderVersion = deps.path("quilt-loader").asText(); }

        List<ModpackFile> files = new ArrayList<>();
        for (JsonNode f : root.path("files")) {
            String clientEnv = f.path("env").path("client").asText("required");
            if ("unsupported".equals(clientEnv)) continue;
            boolean optional = !"required".equals(clientEnv);

            String path = f.path("path").asText();
            String url  = f.path("downloads").isArray() && f.path("downloads").size() > 0
                    ? f.path("downloads").get(0).asText() : "";
            String sha512 = f.path("hashes").path("sha512").asText(null);
            String sha1   = f.path("hashes").path("sha1").asText(null);
            long   size   = f.path("fileSize").asLong(-1L);
            files.add(new ModpackFile(path, url, sha1, sha512, size, !optional, optional));
        }
        return new ModpackManifest(name, packVersion, mcVersion, loaderType, loaderVersion, files, "MODRINTH");
    }

    private ModpackManifest parseCurseForge(JsonNode root) {
        String name        = root.path("name").asText("Modpack");
        String packVersion = root.path("version").asText("1.0.0");
        JsonNode mc        = root.path("minecraft");
        String mcVersion   = mc.path("version").asText("1.20.1");

        String loaderType = "VANILLA", loaderVersion = "";
        for (JsonNode loader : mc.path("modLoaders")) {
            String id = loader.path("id").asText("");
            if (id.startsWith("forge-"))    { loaderType = "FORGE";    loaderVersion = id.substring(6);  break; }
            if (id.startsWith("neoforge-")) { loaderType = "NEOFORGE"; loaderVersion = id.substring(9);  break; }
            if (id.startsWith("fabric-"))   { loaderType = "FABRIC";   loaderVersion = id.substring(7);  break; }
            if (id.startsWith("quilt-"))    { loaderType = "QUILT";    loaderVersion = id.substring(6);  break; }
        }

        List<ModpackFile> files = new ArrayList<>();
        for (JsonNode f : root.path("files")) {
            int projectId = f.path("projectID").asInt();
            int fileId    = f.path("fileID").asInt();
            boolean req   = f.path("required").asBoolean(true);
            // URL marcada como cursor:// para resolver después
            files.add(new ModpackFile(
                    "mods/cf_" + projectId + "_" + fileId + ".jar",
                    "curse://" + projectId + "/" + fileId,
                    null, -1L, req));
        }
        return new ModpackManifest(name, packVersion, mcVersion, loaderType, loaderVersion, files, "CURSEFORGE");
    }

    // ══════════════════════════════════════════════════════════════════════
    //  INSTALACIÓN DE MODS
    // ══════════════════════════════════════════════════════════════════════

    /**
     * Extrae overrides y descarga todos los mods del modpack.
     *
     * @param zipFile  ruta al archivo del modpack
     * @param manifest manifiesto parseado
     * @param gameDir  directorio raíz del juego (instancia)
     * @param progress callback (0-100, mensaje)
     */
    public void installModpackFiles(Path zipFile, ModpackManifest manifest, Path gameDir,
            BiConsumer<Integer, String> progress) throws IOException, InterruptedException {

        progress.accept(0, "Preparando la instancia del perfil...");
        Files.createDirectories(gameDir);

        Set<String> managedPaths = collectManagedPaths(zipFile, manifest);

        progress.accept(2, "Limpiando archivos previos del modpack...");
        purgeManagedContent(gameDir, managedPaths);

        progress.accept(8, "Extrayendo overrides y contenido del modpack...");
        extractOverrides(zipFile, gameDir);

        List<ModpackFile> files = manifest.files();
        if ("CURSEFORGE".equals(manifest.source())) {
            progress.accept(12, "Resolviendo URLs de archivos desde CurseForge...");
            files = resolveCurseForgeUrls(files, progress);
        }

        int total = files.size();
        if (total == 0) {
            writeInstalledState(gameDir, managedPaths);
            progress.accept(100, "Modpack instalado: " + manifest.name());
            return;
        }

        AtomicInteger ready = new AtomicInteger(0);
        List<DownloadItem> tasks = new ArrayList<>();
        for (ModpackFile file : files) {
            if (file.downloadUrl() == null || file.downloadUrl().isBlank()
                    || file.downloadUrl().startsWith("curse://")) {
                ready.incrementAndGet();
                continue;
            }
            Path dest = resolveGamePath(gameDir, file.path());
            if (isValidFile(dest, file.size())) { ready.incrementAndGet(); continue; }
            tasks.add(new DownloadItem(file.downloadUrl(), dest, file.sha1(), file.sha512(), file.size()));
        }

        int preDone = ready.get();
        int initPct = 10 + preDone * 85 / Math.max(total, 1);
        progress.accept(initPct, "Archivos del modpack: " + preDone + "/" + total + " ya presentes.");

        downloadMods(tasks, total, preDone, progress);
        writeInstalledState(gameDir, managedPaths);
        progress.accept(100, "Modpack instalado: " + manifest.name());
    }

    private Set<String> collectManagedPaths(Path zipFile, ModpackManifest manifest) throws IOException {
        Set<String> managed = new LinkedHashSet<>();
        for (ModpackFile file : manifest.files()) {
            String normalized = normalizeRelativePath(file.path());
            if (!normalized.isBlank()) {
                managed.add(normalized);
            }
        }

        try (ZipInputStream zip = new ZipInputStream(Files.newInputStream(zipFile))) {
            ZipEntry entry;
            while ((entry = zip.getNextEntry()) != null) {
                String relative = resolvePackContentRelativePath(entry.getName());
                if (relative != null && !entry.isDirectory()) {
                    String normalized = normalizeRelativePath(relative);
                    if (!normalized.isBlank()) {
                        managed.add(normalized);
                    }
                }
                zip.closeEntry();
            }
        }
        return managed;
    }

    private void purgeManagedContent(Path gameDir, Set<String> nextManagedPaths) throws IOException {
        Set<String> pathsToDelete = new LinkedHashSet<>(loadInstalledState(gameDir));
        if (pathsToDelete.isEmpty()) {
            pathsToDelete.addAll(LEGACY_MANAGED_PATHS);
        }
        pathsToDelete.addAll(nextManagedPaths);

        for (String relativePath : pathsToDelete) {
            deleteRecursively(resolveGamePath(gameDir, relativePath));
        }
        Files.deleteIfExists(gameDir.resolve(MODPACK_STATE_FILE));
    }

    private void extractOverrides(Path zipFile, Path gameDir) throws IOException {
        try (ZipInputStream zip = new ZipInputStream(Files.newInputStream(zipFile))) {
            ZipEntry entry;
            while ((entry = zip.getNextEntry()) != null) {
                String relative = resolvePackContentRelativePath(entry.getName());
                if (relative != null && !entry.isDirectory()) {
                    Path dest = resolveGamePath(gameDir, relative);
                    if (dest.getParent() != null) {
                        Files.createDirectories(dest.getParent());
                    }
                    Files.copy(zip, dest, StandardCopyOption.REPLACE_EXISTING);
                }
                zip.closeEntry();
            }
        }
    }

    private String normalizeZipEntryName(String entryName) {
        return entryName == null ? "" : entryName.replace('\\', '/');
    }

    private boolean isEntryNamed(String entryName, String expectedName) {
        String normalized = normalizeZipEntryName(entryName);
        String expected = expectedName.toLowerCase();
        String lower = normalized.toLowerCase();
        return lower.equals(expected) || lower.endsWith("/" + expected);
    }

    private String resolvePackContentRelativePath(String entryName) {
        String normalized = normalizeZipEntryName(entryName);
        String lower = normalized.toLowerCase();

        if (isMetadataEntry(lower)) {
            return null;
        }

        for (String marker : List.of("overrides/", "client-overrides/")) {
            if (lower.startsWith(marker)) {
                return normalized.substring(marker.length());
            }
            int nested = lower.indexOf("/" + marker);
            if (nested >= 0) {
                return normalized.substring(nested + marker.length() + 1);
            }
        }

        for (String marker : List.of("minecraft/", ".minecraft/")) {
            if (lower.startsWith(marker)) {
                return normalized.substring(marker.length());
            }
            int nested = lower.indexOf("/" + marker);
            if (nested >= 0) {
                return normalized.substring(nested + marker.length() + 1);
            }
        }

        if (isClientContentPath(lower)) {
            return normalized;
        }

        int slash = lower.lastIndexOf('/');
        if (slash >= 0) {
            String tail = lower.substring(slash + 1);
            if (CLIENT_CONTENT_ROOTS.contains(tail)) {
                return normalized.substring(slash + 1);
            }
        }
        return null;
    }

    private boolean isClientContentPath(String lowerPath) {
        for (String root : CLIENT_CONTENT_ROOTS) {
            if (lowerPath.equals(root) || lowerPath.startsWith(root + "/")) {
                return true;
            }
        }
        return false;
    }

    private boolean isMetadataEntry(String lowerPath) {
        return lowerPath.equals("modrinth.index.json")
                || lowerPath.endsWith("/modrinth.index.json")
                || lowerPath.equals("manifest.json")
                || lowerPath.endsWith("/manifest.json")
                || lowerPath.equals("minecraftinstance.json")
                || lowerPath.endsWith("/minecraftinstance.json")
                || lowerPath.equals("instance.cfg")
                || lowerPath.endsWith("/instance.cfg");
    }

    private Path resolveGamePath(Path gameDir, String relativePath) throws IOException {
        String normalizedRelative = normalizeRelativePath(relativePath);
        Path normalizedGameDir = gameDir.toAbsolutePath().normalize();
        Path resolved = normalizedGameDir.resolve(normalizedRelative.replace("/", File.separator)).normalize();
        if (!resolved.startsWith(normalizedGameDir)) {
            throw new IOException("Ruta fuera de la instancia no permitida: " + relativePath);
        }
        return resolved;
    }

    private String normalizeRelativePath(String relativePath) throws IOException {
        if (relativePath == null) {
            throw new IOException("El modpack contiene una ruta nula");
        }

        String normalized = relativePath.replace('\\', '/').trim();
        while (normalized.startsWith("/")) {
            normalized = normalized.substring(1);
        }

        if (normalized.isBlank()) {
            return "";
        }
        if (normalized.matches("^[A-Za-z]:.*")) {
            throw new IOException("Ruta absoluta no permitida en modpack: " + relativePath);
        }

        Path safePath = Path.of(normalized).normalize();
        String result = safePath.toString().replace('\\', '/');
        if (safePath.isAbsolute() || result.equals("..") || result.startsWith("../") || result.isBlank()) {
            throw new IOException("Ruta relativa no valida en modpack: " + relativePath);
        }
        return result;
    }

    private List<ModpackFile> resolveCurseForgeUrls(List<ModpackFile> files,
            BiConsumer<Integer, String> progress) {
        List<ModpackFile> resolved = new ArrayList<>();
        int total = files.size(), done = 0;
        for (ModpackFile f : files) {
            if (!f.downloadUrl().startsWith("curse://")) { resolved.add(f); done++; continue; }
            String[] parts = f.downloadUrl().substring(8).split("/");
            int projectId = Integer.parseInt(parts[0]);
            int fileId    = Integer.parseInt(parts[1]);
            try {
                JsonNode info     = getJson(URI.create(CURSE_API + "/mods/" + projectId + "/files/" + fileId));
                String url        = info.path("data").path("downloadUrl").asText("");
                String fileName   = info.path("data").path("fileName").asText(projectId + "_" + fileId + ".jar");
                if (url.isBlank()) {
                    url = "https://edge.forgecdn.net/files/" + (fileId / 1000) + "/" + (fileId % 1000) + "/" + fileName;
                }
                resolved.add(new ModpackFile("mods/" + fileName, url, null, -1L, f.required()));
            } catch (Exception ex) {
                System.err.println("[modpack] No se pudo resolver " + projectId + "/" + fileId + ": " + ex.getMessage());
                // Mantiene curse:// → será saltado al descargar
                resolved.add(f);
            }
            done++;
            progress.accept(done * 5 / Math.max(total, 1),
                    "Resolviendo mods CurseForge: " + done + "/" + total);
        }
        return resolved;
    }

    private void downloadMods(List<DownloadItem> tasks, int totalMods, int preDone,
            BiConsumer<Integer, String> progress) throws IOException, InterruptedException {
        if (tasks.isEmpty()) return;

        ExecutorService pool        = Executors.newFixedThreadPool(Math.min(MOD_THREADS, tasks.size()));
        CompletionService<Void> cs  = new ExecutorCompletionService<>(pool);
        List<String> failures       = new ArrayList<>();
        AtomicInteger done          = new AtomicInteger(preDone);

        for (DownloadItem task : tasks) {
            cs.submit(() -> {
                if (task.dest().getParent() != null) {
                    Files.createDirectories(task.dest().getParent());
                }
                downloadWithRetry(task.url(), task.dest());
                return null;
            });
        }

        try {
            for (int i = 0; i < tasks.size(); i++) {
                try {
                    cs.take().get();
                } catch (ExecutionException ex) {
                    String msg = ex.getCause() != null ? ex.getCause().getMessage() : ex.getMessage();
                    failures.add(msg);
                }
                int current = done.incrementAndGet();
                int pct = 10 + current * 85 / Math.max(totalMods, 1);
                progress.accept(pct, "Archivos del modpack: " + current + "/" + totalMods + " (" + pct + "%)");
            }
        } finally {
            pool.shutdown();
            pool.awaitTermination(30, TimeUnit.MINUTES);
        }

        if (!failures.isEmpty()) {
            String detail = failures.stream().limit(3)
                    .collect(java.util.stream.Collectors.joining("; "));
            throw new IOException(failures.size() + " mods no se pudieron descargar: " + detail);
        }
    }

    // ══════════════════════════════════════════════════════════════════════
    //  INSTALACIÓN DE LOADERS
    // ══════════════════════════════════════════════════════════════════════

    /**
     * Instala el loader correspondiente y devuelve el versionId de lanzamiento.
     * Si ya está instalado, devuelve directamente el versionId sin repetir.
     */
    public String installLoader(String loaderType, String mcVersion, String loaderVersion,
            Path gameDir, BiConsumer<Integer, String> progress)
            throws IOException, InterruptedException {
        return switch (loaderType.toUpperCase()) {
            case "FORGE"    -> installForge(mcVersion, loaderVersion, gameDir, progress);
            case "NEOFORGE" -> installNeoForge(mcVersion, loaderVersion, gameDir, progress);
            case "FABRIC"   -> installFabric(mcVersion, loaderVersion, gameDir, progress);
            case "QUILT"    -> installQuilt(mcVersion, loaderVersion, gameDir, progress);
            default         -> mcVersion; // VANILLA
        };
    }

    public String installForge(String mcVersion, String forgeVersion, Path gameDir,
            BiConsumer<Integer, String> progress) throws IOException, InterruptedException {
        String versionId  = mcVersion + "-forge-" + forgeVersion;
        Path   versionDir = gameDir.resolve("versions").resolve(versionId);
        if (Files.exists(versionDir.resolve(versionId + ".json"))) {
            progress.accept(100, "Forge " + forgeVersion + " ya instalado.");
            return versionId;
        }

        String url = "https://maven.minecraftforge.net/net/minecraftforge/forge/"
                + mcVersion + "-" + forgeVersion
                + "/forge-" + mcVersion + "-" + forgeVersion + "-installer.jar";
        Path installer = gameDir.resolve("installers")
                .resolve("forge-" + mcVersion + "-" + forgeVersion + "-installer.jar");
        Files.createDirectories(installer.getParent());

        if (!Files.exists(installer)) {
            progress.accept(5, "Descargando Forge installer " + forgeVersion + "...");
            downloadWithRetry(url, installer);
        }

        progress.accept(20, "Instalando Forge " + forgeVersion + "...");
        ensureLauncherProfiles(gameDir);
        runInstaller(installer, gameDir, progress, 20, 95);

        if (!Files.exists(versionDir.resolve(versionId + ".json"))) {
            throw new IOException("Forge no se instaló correctamente en " + versionDir);
        }
        progress.accept(100, "Forge " + forgeVersion + " instalado.");
        return versionId;
    }

    public String installNeoForge(String mcVersion, String neoVersion, Path gameDir,
            BiConsumer<Integer, String> progress) throws IOException, InterruptedException {
        // NeoForge 1.20.2+ → versionId: "neoforge-{ver}"
        // NeoForge 1.20.1  → versionId: "{mcVer}-forge-{ver}" (heredado de Forge)
        boolean isLegacy  = mcVersion.equals("1.20.1");
        String  versionId = isLegacy ? (mcVersion + "-forge-" + neoVersion) : ("neoforge-" + neoVersion);
        Path    versionDir = gameDir.resolve("versions").resolve(versionId);
        if (Files.exists(versionDir.resolve(versionId + ".json"))) {
            progress.accept(100, "NeoForge " + neoVersion + " ya instalado.");
            return versionId;
        }

        String url = isLegacy
                ? "https://maven.neoforged.net/releases/net/neoforged/forge/"
                        + neoVersion + "/forge-" + neoVersion + "-installer.jar"
                : "https://maven.neoforged.net/releases/net/neoforged/neoforge/"
                        + neoVersion + "/neoforge-" + neoVersion + "-installer.jar";

        Path installer = gameDir.resolve("installers").resolve("neoforge-" + neoVersion + "-installer.jar");
        Files.createDirectories(installer.getParent());
        if (!Files.exists(installer)) {
            progress.accept(5, "Descargando NeoForge installer " + neoVersion + "...");
            downloadWithRetry(url, installer);
        }

        progress.accept(20, "Instalando NeoForge " + neoVersion + "...");
        ensureLauncherProfiles(gameDir);
        runInstaller(installer, gameDir, progress, 20, 95);

        if (!Files.exists(versionDir.resolve(versionId + ".json"))) {
            throw new IOException("NeoForge no se instaló correctamente en " + versionDir);
        }
        progress.accept(100, "NeoForge " + neoVersion + " instalado.");
        return versionId;
    }

    public String installFabric(String mcVersion, String loaderVersion, Path gameDir,
            BiConsumer<Integer, String> progress) throws IOException, InterruptedException {
        String versionId  = "fabric-loader-" + loaderVersion + "-" + mcVersion;
        Path   versionDir = gameDir.resolve("versions").resolve(versionId);
        if (Files.exists(versionDir.resolve(versionId + ".json"))) {
            progress.accept(100, "Fabric " + loaderVersion + " ya instalado.");
            return versionId;
        }

        String installerVer = resolveLatestFabricInstaller();
        String url = "https://maven.fabricmc.net/net/fabricmc/fabric-installer/"
                + installerVer + "/fabric-installer-" + installerVer + ".jar";
        Path installer = gameDir.resolve("installers").resolve("fabric-installer-" + installerVer + ".jar");
        Files.createDirectories(installer.getParent());
        if (!Files.exists(installer)) {
            progress.accept(5, "Descargando Fabric installer " + installerVer + "...");
            downloadWithRetry(url, installer);
        }

        progress.accept(20, "Instalando Fabric " + loaderVersion + "...");
        runProcess(new ProcessBuilder(
                "java", "-jar", installer.toAbsolutePath().toString(),
                "client",
                "-mcversion", mcVersion,
                "-loader", loaderVersion,
                "-dir", gameDir.toAbsolutePath().toString(),
                "-noprofile"
        ).redirectErrorStream(true).directory(gameDir.toFile()), progress, 20, 95);

        if (!Files.exists(versionDir.resolve(versionId + ".json"))) {
            throw new IOException("Fabric no se instaló correctamente en " + versionDir);
        }
        progress.accept(100, "Fabric " + loaderVersion + " instalado.");
        return versionId;
    }

    public String installQuilt(String mcVersion, String loaderVersion, Path gameDir,
            BiConsumer<Integer, String> progress) throws IOException, InterruptedException {
        String versionId  = "quilt-loader-" + loaderVersion + "-" + mcVersion;
        Path   versionDir = gameDir.resolve("versions").resolve(versionId);
        if (Files.exists(versionDir.resolve(versionId + ".json"))) {
            progress.accept(100, "Quilt " + loaderVersion + " ya instalado.");
            return versionId;
        }

        String installerVer = resolveLatestQuiltInstaller();
        String url = "https://maven.quiltmc.org/repository/release/org/quiltmc/quilt-installer/"
                + installerVer + "/quilt-installer-" + installerVer + ".jar";
        Path installer = gameDir.resolve("installers").resolve("quilt-installer-" + installerVer + ".jar");
        Files.createDirectories(installer.getParent());
        if (!Files.exists(installer)) {
            progress.accept(5, "Descargando Quilt installer " + installerVer + "...");
            downloadWithRetry(url, installer);
        }

        progress.accept(20, "Instalando Quilt " + loaderVersion + "...");
        runProcess(new ProcessBuilder(
                "java", "-jar", installer.toAbsolutePath().toString(),
                "install", "client", mcVersion, loaderVersion,
                "--install-dir=" + gameDir.toAbsolutePath(),
                "--no-profile"
        ).redirectErrorStream(true).directory(gameDir.toFile()), progress, 20, 95);

        if (!Files.exists(versionDir.resolve(versionId + ".json"))) {
            throw new IOException("Quilt no se instaló correctamente en " + versionDir);
        }
        progress.accept(100, "Quilt " + loaderVersion + " instalado.");
        return versionId;
    }

    // ══════════════════════════════════════════════════════════════════════
    //  VERSIÓN EFECTIVA (sin instalar)
    // ══════════════════════════════════════════════════════════════════════

    /** Devuelve el versionId de lanzamiento dado el loader. No instala nada. */
    public static String computeEffectiveVersionId(String mcVersion, String loaderType, String loaderVersion) {
        if (loaderType == null || loaderType.isBlank() || "VANILLA".equalsIgnoreCase(loaderType)) {
            return mcVersion;
        }
        String lv = loaderVersion == null ? "" : loaderVersion.trim();
        return switch (loaderType.toUpperCase()) {
            case "FORGE"    -> mcVersion + "-forge-" + lv;
            case "NEOFORGE" -> lv.startsWith("2") ? "neoforge-" + lv : mcVersion + "-forge-" + lv;
            case "FABRIC"   -> "fabric-loader-" + lv + "-" + mcVersion;
            case "QUILT"    -> "quilt-loader-" + lv + "-" + mcVersion;
            default         -> mcVersion;
        };
    }

    // ══════════════════════════════════════════════════════════════════════
    //  HELPERS
    // ══════════════════════════════════════════════════════════════════════

    private void runInstaller(Path jar, Path gameDir, BiConsumer<Integer, String> progress,
            int lo, int hi) throws IOException, InterruptedException {
        runProcess(new ProcessBuilder("java", "-jar", jar.toAbsolutePath().toString(), "--installClient")
                .redirectErrorStream(true)
                .directory(gameDir.toFile()), progress, lo, hi);
    }

    private void runProcess(ProcessBuilder pb, BiConsumer<Integer, String> progress,
            int lo, int hi) throws IOException, InterruptedException {
        Process proc = pb.start();
        List<String> lines = new ArrayList<>();
        try (BufferedReader br = new BufferedReader(new InputStreamReader(proc.getInputStream()))) {
            String line;
            while ((line = br.readLine()) != null) {
                lines.add(line);
                // Estima progreso por cantidad de líneas de output
                int estimated = lo + Math.min(lines.size() * 2, hi - lo);
                String msg = line.length() > 80 ? line.substring(0, 80) + "…" : line;
                progress.accept(estimated, msg);
            }
        }
        int exit = proc.waitFor();
        if (exit != 0) {
            throw new IOException("Instalador terminó con código " + exit
                    + (lines.isEmpty() ? "" : ". Último output: " + lines.get(lines.size() - 1)));
        }
    }

    private void ensureLauncherProfiles(Path gameDir) throws IOException {
        Path profiles = gameDir.resolve("launcher_profiles.json");
        if (!Files.exists(profiles)) {
            Files.createDirectories(gameDir);
            Files.writeString(profiles,
                    "{\"profiles\":{},\"selectedProfile\":\"(Default)\","
                    + "\"clientToken\":\"00000000-0000-0000-0000-000000000000\","
                    + "\"launcherVersion\":{\"name\":\"2.0.992\",\"format\":21,\"profilesFormat\":2}}");
        }
    }

    private String resolveLatestFabricInstaller() {
        try {
            JsonNode meta = getJson(URI.create("https://meta.fabricmc.net/v2/versions/installer"));
            if (meta.isArray() && meta.size() > 0) return meta.get(0).path("version").asText("1.0.1");
        } catch (Exception ignored) {}
        return "1.0.1";
    }

    private String resolveLatestQuiltInstaller() {
        try {
            JsonNode meta = getJson(URI.create(
                    "https://meta.quiltmc.org/v3/versions/installer"));
            if (meta.isArray() && meta.size() > 0) return meta.get(0).path("version").asText("0.9.1");
        } catch (Exception ignored) {}
        return "0.9.1";
    }

    private void downloadWithRetry(String url, Path dest) throws IOException, InterruptedException {
        IOException last = null;
        for (int attempt = 1; attempt <= MAX_RETRIES; attempt++) {
            try {
                downloadFile(url, dest);
                return;
            } catch (IOException ex) {
                last = ex;
                if (attempt < MAX_RETRIES) Thread.sleep(600L * attempt);
            }
        }
        throw last;
    }

    private void downloadFile(String url, Path dest) throws IOException, InterruptedException {
        Path tmp = dest.resolveSibling(dest.getFileName() + ".part");
        HttpRequest req = HttpRequest.newBuilder(URI.create(url))
                .timeout(Duration.ofMinutes(10))
                .header("User-Agent", "FroshyLauncher/1.0")
                .GET().build();
        HttpResponse<Path> resp = http.send(req, HttpResponse.BodyHandlers.ofFile(tmp,
                StandardOpenOption.CREATE, StandardOpenOption.WRITE, StandardOpenOption.TRUNCATE_EXISTING));
        if (resp.statusCode() >= 300) {
            Files.deleteIfExists(tmp);
            throw new IOException("HTTP " + resp.statusCode() + " al descargar " + url);
        }
        Files.move(tmp, dest, StandardCopyOption.REPLACE_EXISTING);
    }

    private JsonNode getJson(URI uri) throws IOException, InterruptedException {
        HttpRequest req = HttpRequest.newBuilder(uri)
                .timeout(Duration.ofSeconds(15))
                .header("User-Agent", "FroshyLauncher/1.0")
                .GET().build();
        HttpResponse<String> resp = http.send(req, HttpResponse.BodyHandlers.ofString());
        return mapper.readTree(resp.body());
    }

    private boolean isValidFile(Path p, long minSize) {
        try { return Files.exists(p) && (minSize <= 0 || Files.size(p) >= minSize); }
        catch (IOException e) { return false; }
    }

    private List<String> loadInstalledState(Path gameDir) {
        Path stateFile = gameDir.resolve(MODPACK_STATE_FILE);
        if (!Files.exists(stateFile)) {
            return List.of();
        }
        try {
            InstalledModpackState state = mapper.readValue(stateFile.toFile(), InstalledModpackState.class);
            if (state == null || state.managedPaths == null) {
                return List.of();
            }
            return state.managedPaths.stream().distinct().toList();
        } catch (IOException ex) {
            return List.of();
        }
    }

    private void writeInstalledState(Path gameDir, Set<String> managedPaths) throws IOException {
        InstalledModpackState state = new InstalledModpackState();
        state.managedPaths.addAll(managedPaths.stream().sorted().toList());
        mapper.writerWithDefaultPrettyPrinter().writeValue(gameDir.resolve(MODPACK_STATE_FILE).toFile(), state);
    }

    private void deleteRecursively(Path target) throws IOException {
        if (!Files.exists(target)) {
            return;
        }
        if (!Files.isDirectory(target)) {
            Files.deleteIfExists(target);
            return;
        }
        try (java.util.stream.Stream<Path> walk = Files.walk(target)) {
            walk.sorted(Comparator.reverseOrder()).forEach(path -> {
                try {
                    Files.deleteIfExists(path);
                } catch (IOException ignored) {
                    // Si está bloqueado, se reintentará en la siguiente preparación.
                }
            });
        }
    }

    private static final class InstalledModpackState {
        public List<String> managedPaths = new ArrayList<>();
    }

    private record DownloadItem(String url, Path dest, String sha1, String sha512, long size) {}
}

package am.froshy.launcher.application;

import am.froshy.launcher.domain.ModpackFile;
import am.froshy.launcher.domain.ModpackManifest;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.io.BufferedReader;
import java.io.File;
import java.io.IOException;
import java.io.InputStreamReader;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.StandardCopyOption;
import java.nio.file.StandardOpenOption;
import java.time.Duration;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Set;
import java.util.concurrent.CompletionService;
import java.util.concurrent.ExecutionException;
import java.util.concurrent.ExecutorCompletionService;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.function.BiConsumer;
import java.util.zip.ZipEntry;
import java.util.zip.ZipInputStream;

/**
 * Parsea e instala modpacks en formato Modrinth (.mrpack) y CurseForge (.zip),
 * e instala automáticamente los loaders Forge / NeoForge / Fabric / Quilt.
 */
public final class ModpackInstaller {

    private static final String CURSE_API  = "https://api.curse.tools/v1/cf";
    private static final int    MOD_THREADS = 8;
    private static final int    MAX_RETRIES = 3;
    private static final String MODPACK_STATE_FILE = ".froshy-modpack-state.json";
    private static final List<String> LEGACY_MANAGED_PATHS = List.of(
            "mods",
            "resourcepacks",
            "texturepacks",
            "shaderpacks",
            "config",
            "defaultconfigs",
            "kubejs",
            "datapacks",
            "patchouli_books",
            "options.txt",
            "optionsof.txt",
            "optionsshaders.txt",
            "servers.dat"
    );
    private static final Set<String> CLIENT_CONTENT_ROOTS = Set.of(
            "mods",
            "config",
            "defaultconfigs",
            "resourcepacks",
            "texturepacks",
            "shaderpacks",
            "kubejs",
            "datapacks",
            "patchouli_books",
            "options.txt",
            "optionsof.txt",
            "optionsshaders.txt",
            "servers.dat"
    );
    private static final Set<String> RESERVED_ARCHIVE_ROOTS = Set.of(
            "overrides",
            "client-overrides",
            "minecraft",
            ".minecraft"
    );

    private final HttpClient   http;
    private final ObjectMapper mapper;

    public ModpackInstaller() {
        this.http = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(20))
                .followRedirects(HttpClient.Redirect.ALWAYS)
                .build();
        this.mapper = new ObjectMapper();
    }

    // ══════════════════════════════════════════════════════════════════════
    //  PARSEO
    // ══════════════════════════════════════════════════════════════════════

    /**
     * Parsea un modpack (.mrpack o .zip con manifest.json CurseForge).
     * No descarga nada; sólo devuelve los metadatos y la lista de archivos.
     */
    public ModpackManifest parseModpack(Path zipFile) throws IOException {
        try (ZipInputStream zip = new ZipInputStream(Files.newInputStream(zipFile))) {
            ZipEntry entry;
            while ((entry = zip.getNextEntry()) != null) {
                String name = normalizeZipEntryName(entry.getName());
                if (isEntryNamed(name, "modrinth.index.json")) {
                    return parseModrinth(mapper.readTree(zip.readAllBytes()));
                }
                if (isEntryNamed(name, "manifest.json")) {
                    return parseCurseForge(mapper.readTree(zip.readAllBytes()));
                }
                zip.closeEntry();
            }
        }
        throw new IOException("Formato de modpack no reconocido. " +
                "Se esperaba modrinth.index.json (Modrinth) o manifest.json (CurseForge).");
    }

    private ModpackManifest parseModrinth(JsonNode root) {
        String name        = root.path("name").asText("Modpack");
        String packVersion = root.path("versionId").asText("1.0.0");
        JsonNode deps      = root.path("dependencies");
        String mcVersion   = deps.path("minecraft").asText("1.20.1");

        String loaderType    = "VANILLA";
        String loaderVersion = "";
        if (deps.has("fabric-loader")) { loaderType = "FABRIC";   loaderVersion = deps.path("fabric-loader").asText(); }
        else if (deps.has("forge"))    { loaderType = "FORGE";    loaderVersion = deps.path("forge").asText(); }
        else if (deps.has("neoforge")) { loaderType = "NEOFORGE"; loaderVersion = deps.path("neoforge").asText(); }
        else if (deps.has("quilt-loader")) { loaderType = "QUILT"; loaderVersion = deps.path("quilt-loader").asText(); }

        List<ModpackFile> files = new ArrayList<>();
        for (JsonNode f : root.path("files")) {
            String clientEnv = f.path("env").path("client").asText("required");
            if ("unsupported".equals(clientEnv)) continue;
            boolean optional = !"required".equals(clientEnv);

            String path = f.path("path").asText();
            String url  = f.path("downloads").isArray() && f.path("downloads").size() > 0
                    ? f.path("downloads").get(0).asText() : "";
            String sha512 = f.path("hashes").path("sha512").asText(null);
            String sha1   = f.path("hashes").path("sha1").asText(null);
            long   size   = f.path("fileSize").asLong(-1L);
            files.add(new ModpackFile(path, url, sha1, sha512, size, !optional, optional));
        }
        return new ModpackManifest(name, packVersion, mcVersion, loaderType, loaderVersion, files, "MODRINTH");
    }

    private ModpackManifest parseCurseForge(JsonNode root) {
        String name        = root.path("name").asText("Modpack");
        String packVersion = root.path("version").asText("1.0.0");
        JsonNode mc        = root.path("minecraft");
        String mcVersion   = mc.path("version").asText("1.20.1");

        String loaderType = "VANILLA", loaderVersion = "";
        for (JsonNode loader : mc.path("modLoaders")) {
            String id = loader.path("id").asText("");
            if (id.startsWith("forge-"))    { loaderType = "FORGE";    loaderVersion = id.substring(6);  break; }
            if (id.startsWith("neoforge-")) { loaderType = "NEOFORGE"; loaderVersion = id.substring(9);  break; }
            if (id.startsWith("fabric-"))   { loaderType = "FABRIC";   loaderVersion = id.substring(7);  break; }
            if (id.startsWith("quilt-"))    { loaderType = "QUILT";    loaderVersion = id.substring(6);  break; }
        }

        List<ModpackFile> files = new ArrayList<>();
        for (JsonNode f : root.path("files")) {
            int projectId = f.path("projectID").asInt();
            int fileId    = f.path("fileID").asInt();
            boolean req   = f.path("required").asBoolean(true);
            // URL marcada como cursor:// para resolver después
            files.add(new ModpackFile(
                    "mods/cf_" + projectId + "_" + fileId + ".jar",
                    "curse://" + projectId + "/" + fileId,
                    null, -1L, req));
        }
        return new ModpackManifest(name, packVersion, mcVersion, loaderType, loaderVersion, files, "CURSEFORGE");
    }

    // ══════════════════════════════════════════════════════════════════════
    //  INSTALACIÓN DE MODS
    // ══════════════════════════════════════════════════════════════════════

    /**
     * Extrae overrides y descarga todos los mods del modpack.
     *
     * @param zipFile  ruta al archivo del modpack
     * @param manifest manifiesto parseado
     * @param gameDir  directorio raíz del juego (instancia)
     * @param progress callback (0-100, mensaje)
     */
    public void installModpackFiles(Path zipFile, ModpackManifest manifest, Path gameDir,
            BiConsumer<Integer, String> progress) throws IOException, InterruptedException {

        progress.accept(0, "Preparando la instancia del perfil...");
        Files.createDirectories(gameDir);

        Set<String> managedPaths = collectManagedPaths(zipFile, manifest);

        progress.accept(2, "Limpiando archivos previos del modpack...");
        purgeManagedContent(gameDir, managedPaths);

        progress.accept(8, "Extrayendo overrides y contenido del modpack...");
        extractOverrides(zipFile, gameDir);

        List<ModpackFile> files = manifest.files();
        if ("CURSEFORGE".equals(manifest.source())) {
            progress.accept(12, "Resolviendo URLs de archivos desde CurseForge...");
            files = resolveCurseForgeUrls(files, progress);
        }

        int total = files.size();
        if (total == 0) {
            writeInstalledState(gameDir, managedPaths);
            progress.accept(100, "Modpack instalado: " + manifest.name());
            return;
        }

        AtomicInteger ready = new AtomicInteger(0);
        List<DownloadItem> tasks = new ArrayList<>();
        for (ModpackFile file : files) {
            if (file.downloadUrl() == null || file.downloadUrl().isBlank()
                    || file.downloadUrl().startsWith("curse://")) {
                ready.incrementAndGet();
                continue;
            }
            Path dest = resolveGamePath(gameDir, file.path());
            if (isValidFile(dest, file.size())) { ready.incrementAndGet(); continue; }
            tasks.add(new DownloadItem(file.downloadUrl(), dest, file.sha1(), file.sha512(), file.size()));
        }

        int preDone = ready.get();
        int initPct = 10 + preDone * 85 / Math.max(total, 1);
        progress.accept(initPct, "Archivos del modpack: " + preDone + "/" + total + " ya presentes.");

        downloadMods(tasks, total, preDone, progress);
        writeInstalledState(gameDir, managedPaths);
        progress.accept(100, "Modpack instalado: " + manifest.name());
    }

    private Set<String> collectManagedPaths(Path zipFile, ModpackManifest manifest) throws IOException {
        Set<String> managed = new LinkedHashSet<>();
        String archiveRootPrefix = detectArchiveRootPrefix(zipFile);
        for (ModpackFile file : manifest.files()) {
            String normalized = normalizeRelativePath(file.path());
            if (!normalized.isBlank()) {
                managed.add(normalized);
            }
        }

        try (ZipInputStream zip = new ZipInputStream(Files.newInputStream(zipFile))) {
            ZipEntry entry;
            while ((entry = zip.getNextEntry()) != null) {
                String relative = resolvePackContentRelativePath(entry.getName(), archiveRootPrefix);
                if (relative != null && !entry.isDirectory()) {
                    String normalized = normalizeRelativePath(relative);
                    if (!normalized.isBlank()) {
                        managed.add(normalized);
                    }
                }
                zip.closeEntry();
            }
        }
        return managed;
    }

    private void purgeManagedContent(Path gameDir, Set<String> nextManagedPaths) throws IOException {
        Set<String> pathsToDelete = new LinkedHashSet<>(loadInstalledState(gameDir));
        if (pathsToDelete.isEmpty()) {
            pathsToDelete.addAll(LEGACY_MANAGED_PATHS);
        }
        pathsToDelete.addAll(nextManagedPaths);

        for (String relativePath : pathsToDelete) {
            deleteRecursively(resolveGamePath(gameDir, relativePath));
        }
        Files.deleteIfExists(gameDir.resolve(MODPACK_STATE_FILE));
    }

    private void extractOverrides(Path zipFile, Path gameDir) throws IOException {
        String archiveRootPrefix = detectArchiveRootPrefix(zipFile);
        try (ZipInputStream zip = new ZipInputStream(Files.newInputStream(zipFile))) {
            ZipEntry entry;
            while ((entry = zip.getNextEntry()) != null) {
                String relative = resolvePackContentRelativePath(entry.getName(), archiveRootPrefix);
                if (relative != null && !entry.isDirectory()) {
                    Path dest = resolveGamePath(gameDir, relative);
                    if (dest.getParent() != null) {
                        Files.createDirectories(dest.getParent());
                    }
                    Files.copy(zip, dest, StandardCopyOption.REPLACE_EXISTING);
                }
                zip.closeEntry();
            }
        }
    }

    private String normalizeZipEntryName(String entryName) {
        return entryName == null ? "" : entryName.replace('\\', '/');
    }

    private boolean isEntryNamed(String entryName, String expectedName) {
        String normalized = normalizeZipEntryName(entryName);
        String expected = expectedName.toLowerCase();
        String lower = normalized.toLowerCase();
        return lower.equals(expected) || lower.endsWith("/" + expected);
    }

    private String resolvePackContentRelativePath(String entryName, String archiveRootPrefix) {
        String normalized = stripArchiveRootPrefix(normalizeZipEntryName(entryName), archiveRootPrefix);
        String lower = normalized.toLowerCase();

        if (isMetadataEntry(lower)) {
            return null;
        }

        for (String marker : List.of("overrides/", "client-overrides/")) {
            if (lower.startsWith(marker)) {
                return stripLeadingMinecraftRoot(normalized.substring(marker.length()));
            }
            int nested = lower.indexOf("/" + marker);
            if (nested >= 0) {
                return stripLeadingMinecraftRoot(normalized.substring(nested + marker.length() + 1));
            }
        }

        for (String marker : List.of("minecraft/", ".minecraft/")) {
            if (lower.startsWith(marker)) {
                return normalized.substring(marker.length());
            }
            int nested = lower.indexOf("/" + marker);
            if (nested >= 0) {
                return normalized.substring(nested + marker.length() + 1);
            }
        }

        // Para Modrinth/CurseForge importamos todo el contenido empaquetado
        // (excepto metadata) para incluir config, texturas, shaders y carpetas custom.
        return normalized.isBlank() ? null : normalized;
    }

    private String stripLeadingMinecraftRoot(String path) {
        String current = path == null ? "" : path;
        String lower = current.toLowerCase();
        if (lower.startsWith("minecraft/")) {
            return current.substring("minecraft/".length());
        }
        if (lower.startsWith(".minecraft/")) {
            return current.substring(".minecraft/".length());
        }
        return current;
    }

    private String detectArchiveRootPrefix(Path zipFile) throws IOException {
        Set<String> roots = new LinkedHashSet<>();
        try (ZipInputStream zip = new ZipInputStream(Files.newInputStream(zipFile))) {
            ZipEntry entry;
            while ((entry = zip.getNextEntry()) != null) {
                String normalized = normalizeZipEntryName(entry.getName()).trim();
                if (normalized.isBlank()) {
                    zip.closeEntry();
                    continue;
                }
                if (normalized.startsWith("__MACOSX/")) {
                    zip.closeEntry();
                    continue;
                }
                int slash = normalized.indexOf('/');
                if (slash < 0) {
                    return "";
                }
                roots.add(normalized.substring(0, slash + 1));
                if (roots.size() > 1) {
                    return "";
                }
                zip.closeEntry();
            }
        }

        if (roots.isEmpty()) {
            return "";
        }
        String candidate = roots.iterator().next();
        if (candidate.isBlank()) {
            return "";
        }
        String name = candidate.substring(0, candidate.length() - 1).toLowerCase();
        if (CLIENT_CONTENT_ROOTS.contains(name) || RESERVED_ARCHIVE_ROOTS.contains(name)) {
            return "";
        }
        return candidate;
    }

    private String stripArchiveRootPrefix(String entryName, String archiveRootPrefix) {
        if (archiveRootPrefix == null || archiveRootPrefix.isBlank()) {
            return entryName;
        }
        if (entryName.startsWith(archiveRootPrefix)) {
            return entryName.substring(archiveRootPrefix.length());
        }
        return entryName;
    }

    private boolean isClientContentPath(String lowerPath) {
        for (String root : CLIENT_CONTENT_ROOTS) {
            if (lowerPath.equals(root) || lowerPath.startsWith(root + "/")) {
                return true;
            }
        }
        return false;
    }

    private boolean isMetadataEntry(String lowerPath) {
        return lowerPath.equals("modrinth.index.json")
                || lowerPath.endsWith("/modrinth.index.json")
                || lowerPath.equals("manifest.json")
                || lowerPath.endsWith("/manifest.json")
                || lowerPath.equals("minecraftinstance.json")
                || lowerPath.endsWith("/minecraftinstance.json")
                || lowerPath.equals("instance.cfg")
                || lowerPath.endsWith("/instance.cfg");
    }

    private Path resolveGamePath(Path gameDir, String relativePath) throws IOException {
        String normalizedRelative = normalizeRelativePath(relativePath);
        Path normalizedGameDir = gameDir.toAbsolutePath().normalize();
        Path resolved = normalizedGameDir.resolve(normalizedRelative.replace("/", File.separator)).normalize();
        if (!resolved.startsWith(normalizedGameDir)) {
            throw new IOException("Ruta fuera de la instancia no permitida: " + relativePath);
        }
        return resolved;
    }

    private String normalizeRelativePath(String relativePath) throws IOException {
        if (relativePath == null) {
            throw new IOException("El modpack contiene una ruta nula");
        }

        String normalized = relativePath.replace('\\', '/').trim();
        while (normalized.startsWith("/")) {
            normalized = normalized.substring(1);
        }

        if (normalized.isBlank()) {
            return "";
        }
        if (normalized.matches("^[A-Za-z]:.*")) {
            throw new IOException("Ruta absoluta no permitida en modpack: " + relativePath);
        }

        Path safePath = Path.of(normalized).normalize();
        String result = safePath.toString().replace('\\', '/');
        if (safePath.isAbsolute() || result.equals("..") || result.startsWith("../") || result.isBlank()) {
            throw new IOException("Ruta relativa no valida en modpack: " + relativePath);
        }
        return result;
    }

    private List<ModpackFile> resolveCurseForgeUrls(List<ModpackFile> files,
            BiConsumer<Integer, String> progress) {
        List<ModpackFile> resolved = new ArrayList<>();
        int total = files.size(), done = 0;
        for (ModpackFile f : files) {
            if (!f.downloadUrl().startsWith("curse://")) { resolved.add(f); done++; continue; }
            String[] parts = f.downloadUrl().substring(8).split("/");
            int projectId = Integer.parseInt(parts[0]);
            int fileId    = Integer.parseInt(parts[1]);
            try {
                JsonNode info     = getJson(URI.create(CURSE_API + "/mods/" + projectId + "/files/" + fileId));
                String url        = info.path("data").path("downloadUrl").asText("");
                String fileName   = info.path("data").path("fileName").asText(projectId + "_" + fileId + ".jar");
                if (url.isBlank()) {
                    url = "https://edge.forgecdn.net/files/" + (fileId / 1000) + "/" + (fileId % 1000) + "/" + fileName;
                }
                resolved.add(new ModpackFile("mods/" + fileName, url, null, -1L, f.required()));
            } catch (Exception ex) {
                System.err.println("[modpack] No se pudo resolver " + projectId + "/" + fileId + ": " + ex.getMessage());
                // Mantiene curse:// → será saltado al descargar
                resolved.add(f);
            }
            done++;
            progress.accept(done * 5 / Math.max(total, 1),
                    "Resolviendo mods CurseForge: " + done + "/" + total);
        }
        return resolved;
    }

    private void downloadMods(List<DownloadItem> tasks, int totalMods, int preDone,
            BiConsumer<Integer, String> progress) throws IOException, InterruptedException {
        if (tasks.isEmpty()) return;

        ExecutorService pool        = Executors.newFixedThreadPool(Math.min(MOD_THREADS, tasks.size()));
        CompletionService<Void> cs  = new ExecutorCompletionService<>(pool);
        List<String> failures       = new ArrayList<>();
        AtomicInteger done          = new AtomicInteger(preDone);

        for (DownloadItem task : tasks) {
            cs.submit(() -> {
                if (task.dest().getParent() != null) {
                    Files.createDirectories(task.dest().getParent());
                }
                downloadWithRetry(task.url(), task.dest());
                return null;
            });
        }

        try {
            for (int i = 0; i < tasks.size(); i++) {
                try {
                    cs.take().get();
                } catch (ExecutionException ex) {
                    String msg = ex.getCause() != null ? ex.getCause().getMessage() : ex.getMessage();
                    failures.add(msg);
                }
                int current = done.incrementAndGet();
                int pct = 10 + current * 85 / Math.max(totalMods, 1);
                progress.accept(pct, "Archivos del modpack: " + current + "/" + totalMods + " (" + pct + "%)");
            }
        } finally {
            pool.shutdown();
            pool.awaitTermination(30, TimeUnit.MINUTES);
        }

        if (!failures.isEmpty()) {
            String detail = failures.stream().limit(3)
                    .collect(java.util.stream.Collectors.joining("; "));
            throw new IOException(failures.size() + " mods no se pudieron descargar: " + detail);
        }
    }

    // ══════════════════════════════════════════════════════════════════════
    //  INSTALACIÓN DE LOADERS
    // ══════════════════════════════════════════════════════════════════════

    /**
     * Instala el loader correspondiente y devuelve el versionId de lanzamiento.
     * Si ya está instalado, devuelve directamente el versionId sin repetir.
     */
    public String installLoader(String loaderType, String mcVersion, String loaderVersion,
            Path gameDir, BiConsumer<Integer, String> progress)
            throws IOException, InterruptedException {
        return switch (loaderType.toUpperCase()) {
            case "FORGE"    -> installForge(mcVersion, loaderVersion, gameDir, progress);
            case "NEOFORGE" -> installNeoForge(mcVersion, loaderVersion, gameDir, progress);
            case "FABRIC"   -> installFabric(mcVersion, loaderVersion, gameDir, progress);
            case "QUILT"    -> installQuilt(mcVersion, loaderVersion, gameDir, progress);
            default         -> mcVersion; // VANILLA
        };
    }

    public String installForge(String mcVersion, String forgeVersion, Path gameDir,
            BiConsumer<Integer, String> progress) throws IOException, InterruptedException {
        String versionId  = mcVersion + "-forge-" + forgeVersion;
        Path   versionDir = gameDir.resolve("versions").resolve(versionId);
        if (Files.exists(versionDir.resolve(versionId + ".json"))) {
            progress.accept(100, "Forge " + forgeVersion + " ya instalado.");
            return versionId;
        }

        String url = "https://maven.minecraftforge.net/net/minecraftforge/forge/"
                + mcVersion + "-" + forgeVersion
                + "/forge-" + mcVersion + "-" + forgeVersion + "-installer.jar";
        Path installer = gameDir.resolve("installers")
                .resolve("forge-" + mcVersion + "-" + forgeVersion + "-installer.jar");
        Files.createDirectories(installer.getParent());

        if (!Files.exists(installer)) {
            progress.accept(5, "Descargando Forge installer " + forgeVersion + "...");
            downloadWithRetry(url, installer);
        }

        progress.accept(20, "Instalando Forge " + forgeVersion + "...");
        ensureLauncherProfiles(gameDir);
        runInstaller(installer, gameDir, progress, 20, 95);

        if (!Files.exists(versionDir.resolve(versionId + ".json"))) {
            throw new IOException("Forge no se instaló correctamente en " + versionDir);
        }
        progress.accept(100, "Forge " + forgeVersion + " instalado.");
        return versionId;
    }

    public String installNeoForge(String mcVersion, String neoVersion, Path gameDir,
            BiConsumer<Integer, String> progress) throws IOException, InterruptedException {
        // NeoForge 1.20.2+ → versionId: "neoforge-{ver}"
        // NeoForge 1.20.1  → versionId: "{mcVer}-forge-{ver}" (heredado de Forge)
        boolean isLegacy  = mcVersion.equals("1.20.1");
        String  versionId = isLegacy ? (mcVersion + "-forge-" + neoVersion) : ("neoforge-" + neoVersion);
        Path    versionDir = gameDir.resolve("versions").resolve(versionId);
        if (Files.exists(versionDir.resolve(versionId + ".json"))) {
            progress.accept(100, "NeoForge " + neoVersion + " ya instalado.");
            return versionId;
        }

        String url = isLegacy
                ? "https://maven.neoforged.net/releases/net/neoforged/forge/"
                        + neoVersion + "/forge-" + neoVersion + "-installer.jar"
                : "https://maven.neoforged.net/releases/net/neoforged/neoforge/"
                        + neoVersion + "/neoforge-" + neoVersion + "-installer.jar";

        Path installer = gameDir.resolve("installers").resolve("neoforge-" + neoVersion + "-installer.jar");
        Files.createDirectories(installer.getParent());
        if (!Files.exists(installer)) {
            progress.accept(5, "Descargando NeoForge installer " + neoVersion + "...");
            downloadWithRetry(url, installer);
        }

        progress.accept(20, "Instalando NeoForge " + neoVersion + "...");
        ensureLauncherProfiles(gameDir);
        runInstaller(installer, gameDir, progress, 20, 95);

        if (!Files.exists(versionDir.resolve(versionId + ".json"))) {
            throw new IOException("NeoForge no se instaló correctamente en " + versionDir);
        }
        progress.accept(100, "NeoForge " + neoVersion + " instalado.");
        return versionId;
    }

    public String installFabric(String mcVersion, String loaderVersion, Path gameDir,
            BiConsumer<Integer, String> progress) throws IOException, InterruptedException {
        String versionId  = "fabric-loader-" + loaderVersion + "-" + mcVersion;
        Path   versionDir = gameDir.resolve("versions").resolve(versionId);
        if (Files.exists(versionDir.resolve(versionId + ".json"))) {
            progress.accept(100, "Fabric " + loaderVersion + " ya instalado.");
            return versionId;
        }

        String installerVer = resolveLatestFabricInstaller();
        String url = "https://maven.fabricmc.net/net/fabricmc/fabric-installer/"
                + installerVer + "/fabric-installer-" + installerVer + ".jar";
        Path installer = gameDir.resolve("installers").resolve("fabric-installer-" + installerVer + ".jar");
        Files.createDirectories(installer.getParent());
        if (!Files.exists(installer)) {
            progress.accept(5, "Descargando Fabric installer " + installerVer + "...");
            downloadWithRetry(url, installer);
        }

        progress.accept(20, "Instalando Fabric " + loaderVersion + "...");
        runProcess(new ProcessBuilder(
                "java", "-jar", installer.toAbsolutePath().toString(),
                "client",
                "-mcversion", mcVersion,
                "-loader", loaderVersion,
                "-dir", gameDir.toAbsolutePath().toString(),
                "-noprofile"
        ).redirectErrorStream(true).directory(gameDir.toFile()), progress, 20, 95);

        if (!Files.exists(versionDir.resolve(versionId + ".json"))) {
            throw new IOException("Fabric no se instaló correctamente en " + versionDir);
        }
        progress.accept(100, "Fabric " + loaderVersion + " instalado.");
        return versionId;
    }

    public String installQuilt(String mcVersion, String loaderVersion, Path gameDir,
            BiConsumer<Integer, String> progress) throws IOException, InterruptedException {
        String versionId  = "quilt-loader-" + loaderVersion + "-" + mcVersion;
        Path   versionDir = gameDir.resolve("versions").resolve(versionId);
        if (Files.exists(versionDir.resolve(versionId + ".json"))) {
            progress.accept(100, "Quilt " + loaderVersion + " ya instalado.");
            return versionId;
        }

        String installerVer = resolveLatestQuiltInstaller();
        String url = "https://maven.quiltmc.org/repository/release/org/quiltmc/quilt-installer/"
                + installerVer + "/quilt-installer-" + installerVer + ".jar";
        Path installer = gameDir.resolve("installers").resolve("quilt-installer-" + installerVer + ".jar");
        Files.createDirectories(installer.getParent());
        if (!Files.exists(installer)) {
            progress.accept(5, "Descargando Quilt installer " + installerVer + "...");
            downloadWithRetry(url, installer);
        }

        progress.accept(20, "Instalando Quilt " + loaderVersion + "...");
        runProcess(new ProcessBuilder(
                "java", "-jar", installer.toAbsolutePath().toString(),
                "install", "client", mcVersion, loaderVersion,
                "--install-dir=" + gameDir.toAbsolutePath(),
                "--no-profile"
        ).redirectErrorStream(true).directory(gameDir.toFile()), progress, 20, 95);

        if (!Files.exists(versionDir.resolve(versionId + ".json"))) {
            throw new IOException("Quilt no se instaló correctamente en " + versionDir);
        }
        progress.accept(100, "Quilt " + loaderVersion + " instalado.");
        return versionId;
    }

    // ══════════════════════════════════════════════════════════════════════
    //  VERSIÓN EFECTIVA (sin instalar)
    // ══════════════════════════════════════════════════════════════════════

    /** Devuelve el versionId de lanzamiento dado el loader. No instala nada. */
    public static String computeEffectiveVersionId(String mcVersion, String loaderType, String loaderVersion) {
        if (loaderType == null || loaderType.isBlank() || "VANILLA".equalsIgnoreCase(loaderType)) {
            return mcVersion;
        }
        String lv = loaderVersion == null ? "" : loaderVersion.trim();
        return switch (loaderType.toUpperCase()) {
            case "FORGE"    -> mcVersion + "-forge-" + lv;
            case "NEOFORGE" -> lv.startsWith("2") ? "neoforge-" + lv : mcVersion + "-forge-" + lv;
            case "FABRIC"   -> "fabric-loader-" + lv + "-" + mcVersion;
            case "QUILT"    -> "quilt-loader-" + lv + "-" + mcVersion;
            default         -> mcVersion;
        };
    }

    // ══════════════════════════════════════════════════════════════════════
    //  HELPERS
    // ══════════════════════════════════════════════════════════════════════

    private void runInstaller(Path jar, Path gameDir, BiConsumer<Integer, String> progress,
            int lo, int hi) throws IOException, InterruptedException {
        runProcess(new ProcessBuilder("java", "-jar", jar.toAbsolutePath().toString(), "--installClient")
                .redirectErrorStream(true)
                .directory(gameDir.toFile()), progress, lo, hi);
    }

    private void runProcess(ProcessBuilder pb, BiConsumer<Integer, String> progress,
            int lo, int hi) throws IOException, InterruptedException {
        Process proc = pb.start();
        List<String> lines = new ArrayList<>();
        try (BufferedReader br = new BufferedReader(new InputStreamReader(proc.getInputStream()))) {
            String line;
            while ((line = br.readLine()) != null) {
                lines.add(line);
                // Estima progreso por cantidad de líneas de output
                int estimated = lo + Math.min(lines.size() * 2, hi - lo);
                String msg = line.length() > 80 ? line.substring(0, 80) + "…" : line;
                progress.accept(estimated, msg);
            }
        }
        int exit = proc.waitFor();
        if (exit != 0) {
            throw new IOException("Instalador terminó con código " + exit
                    + (lines.isEmpty() ? "" : ". Último output: " + lines.get(lines.size() - 1)));
        }
    }

    private void ensureLauncherProfiles(Path gameDir) throws IOException {
        Path profiles = gameDir.resolve("launcher_profiles.json");
        if (!Files.exists(profiles)) {
            Files.createDirectories(gameDir);
            Files.writeString(profiles,
                    "{\"profiles\":{},\"selectedProfile\":\"(Default)\","
                    + "\"clientToken\":\"00000000-0000-0000-0000-000000000000\","
                    + "\"launcherVersion\":{\"name\":\"2.0.992\",\"format\":21,\"profilesFormat\":2}}");
        }
    }

    private String resolveLatestFabricInstaller() {
        try {
            JsonNode meta = getJson(URI.create("https://meta.fabricmc.net/v2/versions/installer"));
            if (meta.isArray() && meta.size() > 0) return meta.get(0).path("version").asText("1.0.1");
        } catch (Exception ignored) {}
        return "1.0.1";
    }

    private String resolveLatestQuiltInstaller() {
        try {
            JsonNode meta = getJson(URI.create(
                    "https://meta.quiltmc.org/v3/versions/installer"));
            if (meta.isArray() && meta.size() > 0) return meta.get(0).path("version").asText("0.9.1");
        } catch (Exception ignored) {}
        return "0.9.1";
    }

    private void downloadWithRetry(String url, Path dest) throws IOException, InterruptedException {
        IOException last = null;
        for (int attempt = 1; attempt <= MAX_RETRIES; attempt++) {
            try {
                downloadFile(url, dest);
                return;
            } catch (IOException ex) {
                last = ex;
                if (attempt < MAX_RETRIES) Thread.sleep(600L * attempt);
            }
        }
        throw last;
    }

    private void downloadFile(String url, Path dest) throws IOException, InterruptedException {
        Path tmp = dest.resolveSibling(dest.getFileName() + ".part");
        HttpRequest req = HttpRequest.newBuilder(URI.create(url))
                .timeout(Duration.ofMinutes(10))
                .header("User-Agent", "FroshyLauncher/1.0")
                .GET().build();
        HttpResponse<Path> resp = http.send(req, HttpResponse.BodyHandlers.ofFile(tmp,
                StandardOpenOption.CREATE, StandardOpenOption.WRITE, StandardOpenOption.TRUNCATE_EXISTING));
        if (resp.statusCode() >= 300) {
            Files.deleteIfExists(tmp);
            throw new IOException("HTTP " + resp.statusCode() + " al descargar " + url);
        }
        Files.move(tmp, dest, StandardCopyOption.REPLACE_EXISTING);
    }

    private JsonNode getJson(URI uri) throws IOException, InterruptedException {
        HttpRequest req = HttpRequest.newBuilder(uri)
                .timeout(Duration.ofSeconds(15))
                .header("User-Agent", "FroshyLauncher/1.0")
                .GET().build();
        HttpResponse<String> resp = http.send(req, HttpResponse.BodyHandlers.ofString());
        return mapper.readTree(resp.body());
    }

    private boolean isValidFile(Path p, long minSize) {
        try { return Files.exists(p) && (minSize <= 0 || Files.size(p) >= minSize); }
        catch (IOException e) { return false; }
    }

    private List<String> loadInstalledState(Path gameDir) {
        Path stateFile = gameDir.resolve(MODPACK_STATE_FILE);
        if (!Files.exists(stateFile)) {
            return List.of();
        }
        try {
            InstalledModpackState state = mapper.readValue(stateFile.toFile(), InstalledModpackState.class);
            if (state == null || state.managedPaths == null) {
                return List.of();
            }
            return state.managedPaths.stream().distinct().toList();
        } catch (IOException ex) {
            return List.of();
        }
    }

    private void writeInstalledState(Path gameDir, Set<String> managedPaths) throws IOException {
        InstalledModpackState state = new InstalledModpackState();
        state.managedPaths.addAll(managedPaths.stream().sorted().toList());
        mapper.writerWithDefaultPrettyPrinter().writeValue(gameDir.resolve(MODPACK_STATE_FILE).toFile(), state);
    }

    private void deleteRecursively(Path target) throws IOException {
        if (!Files.exists(target)) {
            return;
        }
        if (!Files.isDirectory(target)) {
            Files.deleteIfExists(target);
            return;
        }
        try (java.util.stream.Stream<Path> walk = Files.walk(target)) {
            walk.sorted(Comparator.reverseOrder()).forEach(path -> {
                try {
                    Files.deleteIfExists(path);
                } catch (IOException ignored) {
                    // Si está bloqueado, se reintentará en la siguiente preparación.
                }
            });
        }
    }

    private static final class InstalledModpackState {
        public List<String> managedPaths = new ArrayList<>();
    }

    private record DownloadItem(String url, Path dest, String sha1, String sha512, long size) {}
}

package am.froshy.launcher.application;

import am.froshy.launcher.config.LauncherVersion;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ArrayNode;
import com.fasterxml.jackson.databind.node.ObjectNode;

import java.io.File;
import java.io.IOException;
import java.io.InputStream;
import java.io.OutputStream;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.StandardCopyOption;
import java.nio.file.StandardOpenOption;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.time.Duration;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.UUID;
import java.util.concurrent.CompletionService;
import java.util.concurrent.ConcurrentLinkedQueue;
import java.util.concurrent.ExecutionException;
import java.util.concurrent.ExecutorCompletionService;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.function.BiConsumer;
import java.util.zip.ZipEntry;
import java.util.zip.ZipInputStream;

public final class MojangVersionDownloader implements MinecraftVersionDownloader {

    private static final URI VERSION_MANIFEST_URI =
            URI.create("https://piston-meta.mojang.com/mc/game/version_manifest_v2.json");
    private static final String ASSETS_BASE = "https://resources.download.minecraft.net/";
    private static final int MAX_RETRIES = 4;
    private static final int LIB_DOWNLOAD_THREADS = 6;
    private static final int ASSET_DOWNLOAD_THREADS = 12;

    // OS detection ──────────────────────────────────────────────────────────
    private static final String OS;
    static {
        String name = System.getProperty("os.name", "").toLowerCase();
        if      (name.contains("win"))                     OS = "windows";
        else if (name.contains("mac") || name.contains("darwin")) OS = "osx";
        else                                               OS = "linux";
    }

    private final HttpClient http;
    private final ObjectMapper mapper;

    public MojangVersionDownloader() {
        this.http = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(20))
                .followRedirects(HttpClient.Redirect.ALWAYS)
                .build();
        this.mapper = new ObjectMapper();
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  downloadVersion — descarga todo lo necesario
    // ═══════════════════════════════════════════════════════════════════════

    @Override
    public void downloadVersion(String version, Path gameDir, BiConsumer<Integer, String> progress)
            throws IOException, InterruptedException {

        // ── Fase 1: manifest + version JSON (0→5 %) ──────────────────────
        progress.accept(0, "Conectando con servidores de Mojang...");
        JsonNode manifest = withRetry("manifest", () -> getJson(VERSION_MANIFEST_URI));
        String versionUrl = findVersionUrl(manifest, version);
        progress.accept(2, "Obteniendo metadatos de version " + version + "...");

        Path versionDir  = gameDir.resolve("versions").resolve(version);
        Path versionJson = versionDir.resolve(version + ".json");
        Files.createDirectories(versionDir);

        JsonNode meta;
        if (Files.exists(versionJson)) {
            meta = mapper.readTree(versionJson.toFile());
        } else {
            meta = withRetry("meta-" + version, () -> getJson(URI.create(versionUrl)));
            mapper.writeValue(versionJson.toFile(), meta);
        }
        progress.accept(5, "Metadatos obtenidos. Descargando JAR del cliente...");

        // ── Fase 2: client JAR (5→35 %) ─────────────────────────────────
        Path clientJar = versionDir.resolve(version + ".jar");
        JsonNode clientNode = meta.path("downloads").path("client");
        String jarUrl = clientNode.path("url").asText();
        if (jarUrl.isBlank()) {
            throw new IOException("Metadatos incompletos para client.jar de " + version);
        }
        long jarSize = clientNode.path("size").asLong(-1L);
        String jarSha1 = textOrNull(clientNode.path("sha1"));
        if (!isValidFile(clientJar, Math.max(1000, jarSize), jarSha1)) {
            withRetryVoid("client-jar", () ->
                    downloadWithProgress(URI.create(jarUrl), clientJar,
                            p -> progress.accept(5 + p * 30 / 100, "Descargando JAR del cliente... " + (5 + p * 30 / 100) + "%"),
                            jarSha1, jarSize));
        }
        progress.accept(35, "JAR del cliente listo. Descargando librerias...");

        // ── Fase 3: librerías (35→68 %) ──────────────────────────────────
        JsonNode libs = meta.path("libraries");
        Path nativesDir = versionDir.resolve("natives");
        Files.createDirectories(nativesDir);
        downloadLibraries(libs, gameDir, nativesDir, progress, 35, 68);

        // ── Fase 4: asset index (68→72 %) ────────────────────────────────
        progress.accept(68, "Descargando indice de assets...");
        String assetIndexId  = meta.path("assetIndex").path("id").asText("legacy");
        String assetIndexUrl = meta.path("assetIndex").path("url").asText();
        Path indexFile = gameDir.resolve("assets").resolve("indexes")
                .resolve(assetIndexId + ".json");
        Files.createDirectories(indexFile.getParent());
        if (!Files.exists(indexFile)) {
            JsonNode indexData = withRetry("asset-index", () -> getJson(URI.create(assetIndexUrl)));
            mapper.writeValue(indexFile.toFile(), indexData);
        }
        progress.accept(72, "Indice de assets listo. Descargando recursos del juego...");

        // ── Fase 5: asset objects (72→100 %) ─────────────────────────────
        JsonNode indexData = mapper.readTree(indexFile.toFile());
        downloadAssets(indexData, gameDir, progress, 72, 100);

        progress.accept(100, "Descarga completada. Listo para jugar!");
    }

    // ── Descarga de librerías ────────────────────────────────────────────

    private void downloadLibraries(JsonNode libs, Path gameDir, Path nativesDir,
            BiConsumer<Integer, String> progress, int lo, int hi) throws IOException, InterruptedException {
        List<DownloadTask> tasks = new ArrayList<>();
        List<Path> nativeArchives = new ArrayList<>();
        int totalUnits = 0;
        int readyUnits = 0;

        for (JsonNode lib : libs) {
            if (!evaluateRules(lib.path("rules"))) continue;

            // Artifact principal → classpath
            JsonNode artifact = lib.path("downloads").path("artifact");
            if (!artifact.isMissingNode() && artifact.has("url")) {
                totalUnits++;
                String relPath = artifact.path("path").asText();
                Path dest = gameDir.resolve("libraries").resolve(relPath);
                long size = artifact.path("size").asLong(-1L);
                String sha1 = textOrNull(artifact.path("sha1"));
                if (!isValidFile(dest, Math.max(4, size), sha1)) {
                    tasks.add(new DownloadTask("lib-" + relPath, URI.create(artifact.path("url").asText()), dest, sha1, size));
                } else {
                    readyUnits++;
                }
            }

            // Natives classifier → extraer a nativesDir
            String nativeKey = getNativeClassifier(lib);
            if (nativeKey != null) {
                JsonNode natArt = lib.path("downloads").path("classifiers").path(nativeKey);
                if (!natArt.isMissingNode() && natArt.has("url")) {
                    totalUnits++;
                    String relPath = natArt.path("path").asText();
                    Path dest = gameDir.resolve("libraries").resolve(relPath);
                    long size = natArt.path("size").asLong(-1L);
                    String sha1 = textOrNull(natArt.path("sha1"));
                    if (!isValidFile(dest, Math.max(4, size), sha1)) {
                        tasks.add(new DownloadTask("native-" + relPath, URI.create(natArt.path("url").asText()), dest, sha1, size));
                    } else {
                        readyUnits++;
                        nativeArchives.add(dest);
                    }
                }
            }
        }

        if (totalUnits == 0) {
            progress.accept(hi, "Sin librerias que descargar.");
            return;
        }

        int initPct = lo + (int) ((long) readyUnits * (hi - lo) / totalUnits);
        progress.accept(initPct, "Librerias: " + readyUnits + "/" + totalUnits + " (" + initPct + "%)");

        int initialReady = readyUnits;
        int totalCount = totalUnits;
        downloadTasks(tasks, Math.min(LIB_DOWNLOAD_THREADS, tasks.size()), (d, t) -> {
            int current = initialReady + d;
            int pct = lo + (int) ((long) current * (hi - lo) / totalCount);
            progress.accept(pct, "Librerias: " + current + "/" + totalCount + " (" + pct + "%)");
        });

        for (DownloadTask task : tasks) {
            if (task.id().startsWith("native-")) {
                nativeArchives.add(task.dest());
            }
        }
        for (Path nativeArchive : nativeArchives) {
            if (isValidFile(nativeArchive, 4)) {
                extractNatives(nativeArchive, nativesDir);
            }
        }

        progress.accept(hi, "Librerias completas.");
    }

    // ── Descarga de assets ───────────────────────────────────────────────

    private void downloadAssets(JsonNode indexData, Path gameDir,
            BiConsumer<Integer, String> progress, int lo, int hi) throws IOException, InterruptedException {
        JsonNode objects = indexData.path("objects");
        List<DownloadTask> pending = new ArrayList<>();
        objects.fields().forEachRemaining(e -> {
            String hash = e.getValue().path("hash").asText();
            String prefix = hash.substring(0, 2);
            Path dest = gameDir.resolve("assets").resolve("objects")
                    .resolve(prefix).resolve(hash);
            long size = e.getValue().path("size").asLong(-1L);
            if (!isValidFile(dest, Math.max(1, size), hash)) {
                pending.add(new DownloadTask("asset-" + hash,
                        URI.create(ASSETS_BASE + prefix + "/" + hash), dest, hash, size));
            }
        });

        int total      = objects.size();
        int preDone    = total - pending.size();
        AtomicInteger done = new AtomicInteger(preDone);
        int initPct = lo + (int)((long) preDone * (hi - lo) / Math.max(total, 1));
        progress.accept(initPct, "Assets: " + preDone + "/" + total + " ya descargados.");

        if (pending.isEmpty()) { progress.accept(hi, "Todos los assets presentes."); return; }

        downloadTasks(pending, Math.min(ASSET_DOWNLOAD_THREADS, pending.size()), (d, t) -> {
            int current = preDone + d;
            done.set(current);
            int pct = lo + (int) ((long) current * (hi - lo) / total);
            progress.accept(pct, "Assets: " + current + "/" + total + " (" + pct + "%)");
        });

        progress.accept(hi, "Assets descargados: " + total + "/" + total);
    }

    private record DownloadTask(String id, URI uri, Path dest, String sha1, long size) {}

    // ═══════════════════════════════════════════════════════════════════════
    //  buildInstallation — construye los argumentos de lanzamiento
    // ═══════════════════════════════════════════════════════════════════════

    @Override
    public VersionInstallation buildInstallation(String version, Path gameDir, String username)
            throws IOException {

        ResolvedVersionData resolved = resolveVersionData(version, gameDir, new HashSet<>());
        JsonNode meta = resolved.meta();
        Path versionDir = gameDir.resolve("versions").resolve(version);

        // ── Classpath: librerías + client JAR cuando corresponda ─────────
        Set<Path> classpath = new LinkedHashSet<>();
        for (JsonNode lib : meta.path("libraries")) {
            if (!evaluateRules(lib.path("rules"))) continue;
            JsonNode artifact = lib.path("downloads").path("artifact");
            if (!artifact.isMissingNode()) {
                Path libFile = gameDir.resolve("libraries")
                        .resolve(artifact.path("path").asText());
                if (Files.exists(libFile)) classpath.add(libFile.toAbsolutePath().normalize());
            }
        }
        if (shouldIncludeClientJar(meta, gameDir)) {
            String clientJarVersion = resolved.clientJarVersion();
            Path clientJar = gameDir.resolve("versions").resolve(clientJarVersion).resolve(clientJarVersion + ".jar");
            if (!Files.exists(clientJar)) {
                clientJar = versionDir.resolve(version + ".jar");
            }
            if (Files.exists(clientJar)) {
                classpath.add(clientJar.toAbsolutePath().normalize());
            }
        }

        // ── Variables de sustitución ─────────────────────────────────────
        String mainClass     = meta.path("mainClass").asText();
        String assetIndexId  = meta.path("assetIndex").path("id").asText("legacy");
        Path   assetsDir     = gameDir.resolve("assets");
        Path   librariesDir  = gameDir.resolve("libraries");
        Path   nativesDir    = versionDir.resolve("natives");

        List<Path> classpathEntries = new ArrayList<>(classpath);

        String cpStr = classpathEntries.stream()
                .map(p -> p.toAbsolutePath().toString())
                .collect(java.util.stream.Collectors.joining(File.pathSeparator));

        Map<String, String> vars = new HashMap<>();
        vars.put("auth_player_name",    username);
        vars.put("version_name",        version);
        vars.put("game_directory",      gameDir.toAbsolutePath().toString());
        vars.put("assets_root",         assetsDir.toAbsolutePath().toString());
        vars.put("assets_index_name",   assetIndexId);
        vars.put("game_assets",         assetsDir.toAbsolutePath().toString());
        vars.put("auth_uuid",           offlineUUID(username).toString());
        vars.put("auth_access_token",   "0");
        vars.put("auth_session",        "0");
        vars.put("clientid",            "0");
        vars.put("auth_xuid",           "0");
        vars.put("user_type",           "offline");
        vars.put("user_properties",     "{}");
        vars.put("profile_name",        username);
        vars.put("version_type",        meta.path("type").asText("release"));
        vars.put("launcher_name",       "FroshyLauncher");
        vars.put("launcher_version",    LauncherVersion.get());
        vars.put("natives_directory",   nativesDir.toAbsolutePath().toString());
        vars.put("library_directory",   librariesDir.toAbsolutePath().toString());
        vars.put("classpath_separator", File.pathSeparator);
        vars.put("classpath",           cpStr);
        vars.put("resolution_width",    "854");
        vars.put("resolution_height",   "480");

        // ── JVM arguments ────────────────────────────────────────────────
        List<String> jvmArgs = new ArrayList<>();
        JsonNode jvmArgsNode = meta.path("arguments").path("jvm");
        if (!jvmArgsNode.isMissingNode() && jvmArgsNode.isArray()) {
            jvmArgs.addAll(processArgNodes(jvmArgsNode, vars));
        } else {
            // Formato antiguo (<1.13): argumentos mínimos
            jvmArgs.add("-Djava.library.path=" + nativesDir.toAbsolutePath());
            jvmArgs.add("-Dminecraft.launcher.brand=FroshyLauncher");
            jvmArgs.add("-Dminecraft.launcher.version=1.0");
            jvmArgs.add("-cp");
            jvmArgs.add(cpStr);
        }

        // ── Game arguments ───────────────────────────────────────────────
        List<String> gameArgs = new ArrayList<>();
        JsonNode gameArgsNode = meta.path("arguments").path("game");
        if (!gameArgsNode.isMissingNode() && gameArgsNode.isArray()) {
            gameArgs.addAll(processArgNodes(gameArgsNode, vars));
        } else if (meta.has("minecraftArguments")) {
            for (String tok : meta.path("minecraftArguments").asText().split(" ")) {
                if (!tok.isBlank()) gameArgs.add(substitute(tok, vars));
            }
        }

        return new VersionInstallation(classpathEntries, mainClass, jvmArgs, gameArgs, nativesDir);
    }

    private boolean shouldIncludeClientJar(JsonNode meta, Path gameDir) {
        return !usesLibraryManagedMinecraftClient(meta, gameDir);
    }

    private boolean usesLibraryManagedMinecraftClient(JsonNode meta, Path gameDir) {
        if (!"cpw.mods.bootstraplauncher.BootstrapLauncher".equals(meta.path("mainClass").asText(""))) {
            return false;
        }

        JsonNode jvmArgs = meta.path("arguments").path("jvm");
        boolean forgeLikeBootstrap = jvmArgs.isArray() && processArgNodes(jvmArgs, Map.of()).stream()
                .anyMatch(arg -> arg.startsWith("-DignoreList=") && arg.contains("client-extra"));
        if (!forgeLikeBootstrap) {
            return false;
        }

        Path minecraftClientLibs = gameDir.resolve("libraries").resolve("net").resolve("minecraft").resolve("client");
        if (!Files.isDirectory(minecraftClientLibs)) {
            return false;
        }

        try (java.util.stream.Stream<Path> walk = Files.walk(minecraftClientLibs, 3)) {
            return walk
                    .filter(Files::isRegularFile)
                    .map(path -> path.getFileName().toString())
                    .anyMatch(name -> name.endsWith("-srg.jar") || name.endsWith("-slim.jar") || name.endsWith("-extra.jar"));
        } catch (IOException ex) {
            return false;
        }
    }

    private ResolvedVersionData resolveVersionData(String version, Path gameDir, Set<String> visiting)
            throws IOException {
        if (!visiting.add(version)) {
            throw new IOException("Cadena de herencia circular detectada en version: " + version);
        }

        Path versionJson = gameDir.resolve("versions").resolve(version).resolve(version + ".json");
        if (!Files.exists(versionJson)) {
            throw new IOException("Version " + version + " no instalada. Falta: " + versionJson);
        }

        ObjectNode current = (ObjectNode) mapper.readTree(versionJson.toFile());
        String parentId = current.path("inheritsFrom").asText("");

        if (parentId.isBlank()) {
            visiting.remove(version);
            return new ResolvedVersionData(current, findClientJarVersion(version, gameDir, new HashSet<>()));
        }

        ResolvedVersionData parent = resolveVersionData(parentId, gameDir, visiting);
        ObjectNode merged = mergeVersionMeta((ObjectNode) parent.meta(), current);
        visiting.remove(version);
        return new ResolvedVersionData(merged, findClientJarVersion(version, gameDir, new HashSet<>()));
    }

    private String findClientJarVersion(String version, Path gameDir, Set<String> visiting) throws IOException {
        if (!visiting.add(version)) {
            throw new IOException("Cadena de herencia circular al resolver JAR cliente: " + version);
        }

        Path versionDir = gameDir.resolve("versions").resolve(version);
        Path jar = versionDir.resolve(version + ".jar");
        Path json = versionDir.resolve(version + ".json");
        if (!Files.exists(json)) {
            throw new IOException("Version " + version + " no instalada. Falta: " + json);
        }

        ObjectNode meta = (ObjectNode) mapper.readTree(json.toFile());
        if (Files.exists(jar) || meta.path("downloads").path("client").has("url")) {
            return version;
        }

        String parent = meta.path("inheritsFrom").asText("");
        if (parent.isBlank()) {
            return version;
        }

        return findClientJarVersion(parent, gameDir, visiting);
    }

    private ObjectNode mergeVersionMeta(ObjectNode parent, ObjectNode child) {
        ObjectNode merged = parent.deepCopy();

        child.fields().forEachRemaining(entry -> {
            String field = entry.getKey();
            if ("libraries".equals(field) || "arguments".equals(field)) {
                return;
            }
            merged.set(field, entry.getValue());
        });

        ArrayNode mergedLibraries = mapper.createArrayNode();
        JsonNode parentLibraries = parent.path("libraries");
        if (parentLibraries.isArray()) {
            parentLibraries.forEach(mergedLibraries::add);
        }
        JsonNode childLibraries = child.path("libraries");
        if (childLibraries.isArray()) {
            childLibraries.forEach(mergedLibraries::add);
        }
        merged.set("libraries", mergedLibraries);

        ObjectNode mergedArguments = mapper.createObjectNode();
        JsonNode parentArgs = parent.path("arguments");
        JsonNode childArgs = child.path("arguments");
        mergeArgumentArray(parentArgs, childArgs, mergedArguments, "jvm");
        mergeArgumentArray(parentArgs, childArgs, mergedArguments, "game");
        if (!mergedArguments.isEmpty()) {
            merged.set("arguments", mergedArguments);
        }

        return merged;
    }

    private void mergeArgumentArray(JsonNode parentArgs, JsonNode childArgs, ObjectNode mergedArguments, String key) {
        ArrayNode merged = mapper.createArrayNode();

        if (parentArgs.isObject() && parentArgs.path(key).isArray()) {
            parentArgs.path(key).forEach(merged::add);
        }
        if (childArgs.isObject() && childArgs.path(key).isArray()) {
            childArgs.path(key).forEach(merged::add);
        }

        if (!merged.isEmpty()) {
            mergedArguments.set(key, merged);
        }
    }

    private record ResolvedVersionData(JsonNode meta, String clientJarVersion) {}


    // ═══════════════════════════════════════════════════════════════════════
    //  Helpers de argumentos
    // ═══════════════════════════════════════════════════════════════════════

    private List<String> processArgNodes(JsonNode nodes, Map<String, String> vars) {
        List<String> result = new ArrayList<>();
        for (JsonNode node : nodes) {
            if (node.isTextual()) {
                result.add(substitute(node.asText(), vars));
            } else if (node.isObject()) {
                JsonNode rules = node.path("rules");
                // Ignorar nodos con "features" (demo, custom resolution) excepto si los soportamos
                if (!node.path("rules").isMissingNode()
                        && node.path("rules").toString().contains("features")) {
                    continue;
                }
                if (evaluateRules(rules)) {
                    JsonNode val = node.path("value");
                    if (val.isTextual()) {
                        result.add(substitute(val.asText(), vars));
                    } else if (val.isArray()) {
                        val.forEach(v -> result.add(substitute(v.asText(), vars)));
                    }
                }
            }
        }
        return result;
    }

    private String substitute(String template, Map<String, String> vars) {
        String result = template;
        for (Map.Entry<String, String> e : vars.entrySet()) {
            result = result.replace("${" + e.getKey() + "}", e.getValue());
        }
        return result;
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  Helpers de reglas OS
    // ═══════════════════════════════════════════════════════════════════════

    private boolean evaluateRules(JsonNode rules) {
        if (rules == null || rules.isMissingNode() || rules.isEmpty()) return true;
        boolean allowed = false;
        for (JsonNode rule : rules) {
            String action = rule.path("action").asText("allow");
            boolean match = true;
            JsonNode os = rule.path("os");
            if (!os.isMissingNode()) {
                String reqOs = os.path("name").asText("");
                if (!reqOs.isEmpty() && !reqOs.equals(OS)) match = false;
            }
            // Ignorar reglas de "features" (se manejan por separado)
            if (!rule.path("features").isMissingNode()) match = false;
            if (match) allowed = "allow".equals(action);
        }
        return allowed;
    }

    private String getNativeClassifier(JsonNode lib) {
        JsonNode natives = lib.path("natives");
        if (natives.isMissingNode()) return null;
        JsonNode cls = natives.path(OS);
        if (cls.isMissingNode()) return null;
        String arch = System.getProperty("os.arch", "").contains("64") ? "64" : "32";
        return cls.asText().replace("${arch}", arch);
    }

    private String findVersionUrl(JsonNode manifest, String version) throws IOException {
        for (JsonNode v : manifest.path("versions")) {
            if (version.equals(v.path("id").asText())) {
                return v.path("url").asText();
            }
        }
        throw new IOException("Version de Minecraft no encontrada en manifest: " + version);
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  Helpers de descarga HTTP
    // ═══════════════════════════════════════════════════════════════════════

    private JsonNode getJson(URI uri) throws IOException, InterruptedException {
        HttpRequest req = HttpRequest.newBuilder(uri)
                .timeout(Duration.ofSeconds(30))
                .header("User-Agent", "FroshyLauncher/1.0")
                .GET().build();
        HttpResponse<String> res = http.send(req, HttpResponse.BodyHandlers.ofString());
        if (res.statusCode() >= 300)
            throw new IOException("HTTP " + res.statusCode() + " → " + uri);
        return mapper.readTree(res.body());
    }

    private void downloadWithProgress(URI uri, Path dest, java.util.function.IntConsumer progress,
            String expectedSha1, long expectedSize) throws IOException, InterruptedException {
        HttpRequest req = HttpRequest.newBuilder(uri)
                .timeout(Duration.ofMinutes(5))
                .header("User-Agent", "FroshyLauncher/1.0")
                .GET().build();
        HttpResponse<InputStream> res = http.send(req, HttpResponse.BodyHandlers.ofInputStream());
        if (res.statusCode() >= 300)
            throw new IOException("HTTP " + res.statusCode() + " → " + uri);

        long total = res.headers().firstValueAsLong("Content-Length").orElse(-1L);
        Path tmp   = dest.resolveSibling(dest.getFileName() + ".part");
        Files.createDirectories(dest.getParent());

        try (InputStream in  = res.body();
             OutputStream out = Files.newOutputStream(tmp,
                     StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING)) {
            byte[] buf = new byte[16384];
            long read = 0; int n;
            while ((n = in.read(buf)) != -1) {
                out.write(buf, 0, n);
                read += n;
                if (total > 0) progress.accept((int)(read * 100 / total));
            }
        }
        verifyDownloadedFile(tmp, expectedSha1, expectedSize, uri);
        Files.move(tmp, dest, StandardCopyOption.REPLACE_EXISTING);
    }

    private void downloadSimple(URI uri, Path dest, String expectedSha1, long expectedSize)
            throws IOException, InterruptedException {
        Path tmp = dest.resolveSibling(dest.getFileName() + ".part");
        HttpRequest req = HttpRequest.newBuilder(uri)
                .timeout(Duration.ofMinutes(2))
                .header("User-Agent", "FroshyLauncher/1.0")
                .GET().build();
        HttpResponse<Path> res = http.send(req,
                HttpResponse.BodyHandlers.ofFile(tmp,
                        StandardOpenOption.CREATE,
                        StandardOpenOption.WRITE,
                        StandardOpenOption.TRUNCATE_EXISTING));
        if (res.statusCode() >= 300) {
            Files.deleteIfExists(tmp);
            throw new IOException("HTTP " + res.statusCode() + " → " + uri);
        }
        verifyDownloadedFile(tmp, expectedSha1, expectedSize, uri);
        Files.move(tmp, dest, StandardCopyOption.REPLACE_EXISTING);
    }

    private void verifyDownloadedFile(Path file, String expectedSha1, long expectedSize, URI uri) throws IOException {
        if (expectedSize > 0 && Files.size(file) != expectedSize) {
            throw new IOException("Tamano invalido para " + uri + " (esperado=" + expectedSize
                    + ", real=" + Files.size(file) + ")");
        }
        if (expectedSha1 != null && !expectedSha1.isBlank()) {
            String actual = sha1Hex(file);
            if (!expectedSha1.equalsIgnoreCase(actual)) {
                throw new IOException("SHA1 invalido para " + uri + " (esperado=" + expectedSha1
                        + ", real=" + actual + ")");
            }
        }
    }

    private void downloadTasks(List<DownloadTask> tasks, int threads,
            BiConsumer<Integer, Integer> onProgress) throws IOException, InterruptedException {
        if (tasks.isEmpty()) return;

        ExecutorService pool = Executors.newFixedThreadPool(Math.max(1, threads));
        CompletionService<Void> completion = new ExecutorCompletionService<>(pool);
        ConcurrentLinkedQueue<String> failures = new ConcurrentLinkedQueue<>();

        for (DownloadTask task : tasks) {
            completion.submit(() -> {
                Files.createDirectories(task.dest().getParent());
                withRetryVoid(task.id(), () -> downloadSimple(task.uri(), task.dest(), task.sha1(), task.size()));
                return null;
            });
        }

        try {
            for (int i = 1; i <= tasks.size(); i++) {
                try {
                    completion.take().get();
                } catch (ExecutionException ex) {
                    Throwable cause = ex.getCause() != null ? ex.getCause() : ex;
                    failures.add(cause.getMessage());
                }
                onProgress.accept(i, tasks.size());
            }
        } finally {
            pool.shutdown();
            if (!pool.awaitTermination(60, TimeUnit.MINUTES)) {
                pool.shutdownNow();
            }
        }

        if (!failures.isEmpty()) {
            String detail = failures.stream().limit(3).collect(java.util.stream.Collectors.joining(" | "));
            throw new IOException("Descargas incompletas (" + failures.size() + " fallos): " + detail);
        }
    }

    // ── Extracción de nativos ────────────────────────────────────────────

    private void extractNatives(Path nativeJar, Path nativesDir) throws IOException {
        Files.createDirectories(nativesDir);
        try (ZipInputStream zip = new ZipInputStream(Files.newInputStream(nativeJar))) {
            ZipEntry entry;
            while ((entry = zip.getNextEntry()) != null) {
                String name = entry.getName();
                if (name.startsWith("META-INF/")) { zip.closeEntry(); continue; }
                if (name.endsWith(".dll") || name.endsWith(".so")
                        || name.endsWith(".dylib") || name.endsWith(".jnilib")) {
                    Path target = nativesDir.resolve(Path.of(name).getFileName());
                    if (!Files.exists(target)) {
                        Files.copy(zip, target, StandardCopyOption.REPLACE_EXISTING);
                    }
                }
                zip.closeEntry();
            }
        }
    }

    // ── Utilidades ───────────────────────────────────────────────────────

    private boolean isValidFile(Path p, long minSize) {
        try { return Files.exists(p) && Files.size(p) >= minSize; }
        catch (IOException e) { return false; }
    }

    private boolean isValidFile(Path p, long minSize, String expectedSha1) {
        try {
            if (!Files.exists(p) || Files.size(p) < minSize) return false;
            if (expectedSha1 == null || expectedSha1.isBlank()) return true;
            return expectedSha1.equalsIgnoreCase(sha1Hex(p));
        } catch (IOException e) {
            return false;
        }
    }

    private String textOrNull(JsonNode node) {
        if (node == null || node.isMissingNode()) return null;
        String value = node.asText("").trim();
        return value.isEmpty() ? null : value;
    }

    private String sha1Hex(Path file) throws IOException {
        MessageDigest md;
        try {
            md = MessageDigest.getInstance("SHA-1");
        } catch (NoSuchAlgorithmException ex) {
            throw new IllegalStateException("SHA-1 no disponible", ex);
        }

        try (InputStream in = Files.newInputStream(file)) {
            byte[] buf = new byte[16_384];
            int n;
            while ((n = in.read(buf)) != -1) {
                md.update(buf, 0, n);
            }
        }
        return toHex(md.digest());
    }

    private String toHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder(bytes.length * 2);
        for (byte b : bytes) {
            sb.append(Character.forDigit((b >>> 4) & 0xF, 16));
            sb.append(Character.forDigit(b & 0xF, 16));
        }
        return sb.toString();
    }

    private static UUID offlineUUID(String username) {
        return UUID.nameUUIDFromBytes(
                ("OfflinePlayer:" + username).getBytes(StandardCharsets.UTF_8));
    }

    // ── Retry helpers ────────────────────────────────────────────────────

    private <T> T withRetry(String op, ThrowingSupplier<T> s) throws IOException, InterruptedException {
        IOException last = null;
        for (int i = 1; i <= MAX_RETRIES; i++) {
            try { return s.get(); }
            catch (IOException ex) {
                last = ex;
                if (i < MAX_RETRIES) Thread.sleep(500L * i);
            }
        }
        throw new IOException("Falló " + op + " tras " + MAX_RETRIES + " intentos", last);
    }

    private void withRetryVoid(String op, ThrowingRunnable r) throws IOException, InterruptedException {
        withRetry(op, () -> { r.run(); return null; });
    }

    @FunctionalInterface private interface ThrowingSupplier<T> {
        T get() throws IOException, InterruptedException;
    }
    @FunctionalInterface private interface ThrowingRunnable {
        void run() throws IOException, InterruptedException;
    }
}

package am.froshy.launcher.application;

import am.froshy.launcher.config.LauncherVersion;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ArrayNode;
import com.fasterxml.jackson.databind.node.ObjectNode;

import java.io.File;
import java.io.IOException;
import java.io.InputStream;
import java.io.OutputStream;
import java.net.URI;
import java.net.URLEncoder;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.StandardCopyOption;
import java.nio.file.StandardOpenOption;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.time.Duration;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.UUID;
import java.util.concurrent.CompletionService;
import java.util.concurrent.ConcurrentLinkedQueue;
import java.util.concurrent.ExecutionException;
import java.util.concurrent.ExecutorCompletionService;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.function.BiConsumer;
import java.util.zip.ZipEntry;
import java.util.zip.ZipInputStream;

public final class MojangVersionDownloader implements MinecraftVersionDownloader {

    private static final URI VERSION_MANIFEST_URI =
            URI.create("https://piston-meta.mojang.com/mc/game/version_manifest_v2.json");
    private static final String MOJANG_PROFILE_API = "https://api.mojang.com/users/profiles/minecraft/";
    private static final String ASSETS_BASE = "https://resources.download.minecraft.net/";
    private static final int MAX_RETRIES = 4;
    private static final int LIB_DOWNLOAD_THREADS = 6;
    private static final int ASSET_DOWNLOAD_THREADS = 12;

    // OS detection ──────────────────────────────────────────────────────────
    private static final String OS;
    static {
        String name = System.getProperty("os.name", "").toLowerCase();
        if      (name.contains("win"))                     OS = "windows";
        else if (name.contains("mac") || name.contains("darwin")) OS = "osx";
        else                                               OS = "linux";
    }

    private final HttpClient http;
    private final ObjectMapper mapper;
    private final PremiumUuidResolver premiumUuidResolver;

    public MojangVersionDownloader() {
        this(null);
    }

    MojangVersionDownloader(PremiumUuidResolver premiumUuidResolver) {
        this.http = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(20))
                .followRedirects(HttpClient.Redirect.ALWAYS)
                .build();
        this.mapper = new ObjectMapper();
        this.premiumUuidResolver = premiumUuidResolver != null
                ? premiumUuidResolver
                : this::resolvePremiumUuidFromMojang;
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  downloadVersion — descarga todo lo necesario
    // ═══════════════════════════════════════════════════════════════════════

    @Override
    public void downloadVersion(String version, Path gameDir, BiConsumer<Integer, String> progress)
            throws IOException, InterruptedException {

        // ── Fase 1: manifest + version JSON (0→5 %) ──────────────────────
        progress.accept(0, "Conectando con servidores de Mojang...");
        JsonNode manifest = withRetry("manifest", () -> getJson(VERSION_MANIFEST_URI));
        String versionUrl = findVersionUrl(manifest, version);
        progress.accept(2, "Obteniendo metadatos de version " + version + "...");

        Path versionDir  = gameDir.resolve("versions").resolve(version);
        Path versionJson = versionDir.resolve(version + ".json");
        Files.createDirectories(versionDir);

        JsonNode meta;
        if (Files.exists(versionJson)) {
            meta = mapper.readTree(versionJson.toFile());
        } else {
            meta = withRetry("meta-" + version, () -> getJson(URI.create(versionUrl)));
            mapper.writeValue(versionJson.toFile(), meta);
        }
        progress.accept(5, "Metadatos obtenidos. Descargando JAR del cliente...");

        // ── Fase 2: client JAR (5→35 %) ─────────────────────────────────
        Path clientJar = versionDir.resolve(version + ".jar");
        JsonNode clientNode = meta.path("downloads").path("client");
        String jarUrl = clientNode.path("url").asText();
        if (jarUrl.isBlank()) {
            throw new IOException("Metadatos incompletos para client.jar de " + version);
        }
        long jarSize = clientNode.path("size").asLong(-1L);
        String jarSha1 = textOrNull(clientNode.path("sha1"));
        if (!isValidFile(clientJar, Math.max(1000, jarSize), jarSha1)) {
            withRetryVoid("client-jar", () ->
                    downloadWithProgress(URI.create(jarUrl), clientJar,
                            p -> progress.accept(5 + p * 30 / 100, "Descargando JAR del cliente... " + (5 + p * 30 / 100) + "%"),
                            jarSha1, jarSize));
        }
        progress.accept(35, "JAR del cliente listo. Descargando librerias...");

        // ── Fase 3: librerías (35→68 %) ──────────────────────────────────
        JsonNode libs = meta.path("libraries");
        Path nativesDir = versionDir.resolve("natives");
        Files.createDirectories(nativesDir);
        downloadLibraries(libs, gameDir, nativesDir, progress, 35, 68);

        // ── Fase 4: asset index (68→72 %) ────────────────────────────────
        progress.accept(68, "Descargando indice de assets...");
        String assetIndexId  = meta.path("assetIndex").path("id").asText("legacy");
        String assetIndexUrl = meta.path("assetIndex").path("url").asText();
        Path indexFile = gameDir.resolve("assets").resolve("indexes")
                .resolve(assetIndexId + ".json");
        Files.createDirectories(indexFile.getParent());
        if (!Files.exists(indexFile)) {
            JsonNode indexData = withRetry("asset-index", () -> getJson(URI.create(assetIndexUrl)));
            mapper.writeValue(indexFile.toFile(), indexData);
        }
        progress.accept(72, "Indice de assets listo. Descargando recursos del juego...");

        // ── Fase 5: asset objects (72→100 %) ─────────────────────────────
        JsonNode indexData = mapper.readTree(indexFile.toFile());
        downloadAssets(indexData, gameDir, progress, 72, 100);

        progress.accept(100, "Descarga completada. Listo para jugar!");
    }

    // ── Descarga de librerías ────────────────────────────────────────────

    private void downloadLibraries(JsonNode libs, Path gameDir, Path nativesDir,
            BiConsumer<Integer, String> progress, int lo, int hi) throws IOException, InterruptedException {
        List<DownloadTask> tasks = new ArrayList<>();
        List<Path> nativeArchives = new ArrayList<>();
        int totalUnits = 0;
        int readyUnits = 0;

        for (JsonNode lib : libs) {
            if (!evaluateRules(lib.path("rules"))) continue;

            // Artifact principal → classpath
            JsonNode artifact = lib.path("downloads").path("artifact");
            if (!artifact.isMissingNode() && artifact.has("url")) {
                totalUnits++;
                String relPath = artifact.path("path").asText();
                Path dest = gameDir.resolve("libraries").resolve(relPath);
                long size = artifact.path("size").asLong(-1L);
                String sha1 = textOrNull(artifact.path("sha1"));
                if (!isValidFile(dest, Math.max(4, size), sha1)) {
                    tasks.add(new DownloadTask("lib-" + relPath, URI.create(artifact.path("url").asText()), dest, sha1, size));
                } else {
                    readyUnits++;
                }
            }

            // Natives classifier → extraer a nativesDir
            String nativeKey = getNativeClassifier(lib);
            if (nativeKey != null) {
                JsonNode natArt = lib.path("downloads").path("classifiers").path(nativeKey);
                if (!natArt.isMissingNode() && natArt.has("url")) {
                    totalUnits++;
                    String relPath = natArt.path("path").asText();
                    Path dest = gameDir.resolve("libraries").resolve(relPath);
                    long size = natArt.path("size").asLong(-1L);
                    String sha1 = textOrNull(natArt.path("sha1"));
                    if (!isValidFile(dest, Math.max(4, size), sha1)) {
                        tasks.add(new DownloadTask("native-" + relPath, URI.create(natArt.path("url").asText()), dest, sha1, size));
                    } else {
                        readyUnits++;
                        nativeArchives.add(dest);
                    }
                }
            }
        }

        if (totalUnits == 0) {
            progress.accept(hi, "Sin librerias que descargar.");
            return;
        }

        int initPct = lo + (int) ((long) readyUnits * (hi - lo) / totalUnits);
        progress.accept(initPct, "Librerias: " + readyUnits + "/" + totalUnits + " (" + initPct + "%)");

        int initialReady = readyUnits;
        int totalCount = totalUnits;
        downloadTasks(tasks, Math.min(LIB_DOWNLOAD_THREADS, tasks.size()), (d, t) -> {
            int current = initialReady + d;
            int pct = lo + (int) ((long) current * (hi - lo) / totalCount);
            progress.accept(pct, "Librerias: " + current + "/" + totalCount + " (" + pct + "%)");
        });

        for (DownloadTask task : tasks) {
            if (task.id().startsWith("native-")) {
                nativeArchives.add(task.dest());
            }
        }
        for (Path nativeArchive : nativeArchives) {
            if (isValidFile(nativeArchive, 4)) {
                extractNatives(nativeArchive, nativesDir);
            }
        }

        progress.accept(hi, "Librerias completas.");
    }

    // ── Descarga de assets ───────────────────────────────────────────────

    private void downloadAssets(JsonNode indexData, Path gameDir,
            BiConsumer<Integer, String> progress, int lo, int hi) throws IOException, InterruptedException {
        JsonNode objects = indexData.path("objects");
        List<DownloadTask> pending = new ArrayList<>();
        objects.fields().forEachRemaining(e -> {
            String hash = e.getValue().path("hash").asText();
            String prefix = hash.substring(0, 2);
            Path dest = gameDir.resolve("assets").resolve("objects")
                    .resolve(prefix).resolve(hash);
            long size = e.getValue().path("size").asLong(-1L);
            if (!isValidFile(dest, Math.max(1, size), hash)) {
                pending.add(new DownloadTask("asset-" + hash,
                        URI.create(ASSETS_BASE + prefix + "/" + hash), dest, hash, size));
            }
        });

        int total      = objects.size();
        int preDone    = total - pending.size();
        AtomicInteger done = new AtomicInteger(preDone);
        int initPct = lo + (int)((long) preDone * (hi - lo) / Math.max(total, 1));
        progress.accept(initPct, "Assets: " + preDone + "/" + total + " ya descargados.");

        if (pending.isEmpty()) { progress.accept(hi, "Todos los assets presentes."); return; }

        downloadTasks(pending, Math.min(ASSET_DOWNLOAD_THREADS, pending.size()), (d, t) -> {
            int current = preDone + d;
            done.set(current);
            int pct = lo + (int) ((long) current * (hi - lo) / total);
            progress.accept(pct, "Assets: " + current + "/" + total + " (" + pct + "%)");
        });

        progress.accept(hi, "Assets descargados: " + total + "/" + total);
    }

    private record DownloadTask(String id, URI uri, Path dest, String sha1, long size) {}

    // ═══════════════════════════════════════════════════════════════════════
    //  buildInstallation — construye los argumentos de lanzamiento
    // ═══════════════════════════════════════════════════════════════════════

    @Override
    public VersionInstallation buildInstallation(String version, Path gameDir, String username)
            throws IOException {

        ResolvedVersionData resolved = resolveVersionData(version, gameDir, new HashSet<>());
        JsonNode meta = resolved.meta();
        Path versionDir = gameDir.resolve("versions").resolve(version);

        // ── Classpath: librerías + client JAR cuando corresponda ─────────
        Set<Path> classpath = new LinkedHashSet<>();
        for (JsonNode lib : meta.path("libraries")) {
            if (!evaluateRules(lib.path("rules"))) continue;
            JsonNode artifact = lib.path("downloads").path("artifact");
            if (!artifact.isMissingNode()) {
                Path libFile = gameDir.resolve("libraries")
                        .resolve(artifact.path("path").asText());
                if (Files.exists(libFile)) classpath.add(libFile.toAbsolutePath().normalize());
            }
        }
        if (shouldIncludeClientJar(meta, gameDir)) {
            String clientJarVersion = resolved.clientJarVersion();
            Path clientJar = gameDir.resolve("versions").resolve(clientJarVersion).resolve(clientJarVersion + ".jar");
            if (!Files.exists(clientJar)) {
                clientJar = versionDir.resolve(version + ".jar");
            }
            if (Files.exists(clientJar)) {
                classpath.add(clientJar.toAbsolutePath().normalize());
            }
        }

        // ── Variables de sustitución ─────────────────────────────────────
        String mainClass     = meta.path("mainClass").asText();
        String assetIndexId  = meta.path("assetIndex").path("id").asText("legacy");
        Path   assetsDir     = gameDir.resolve("assets");
        Path   librariesDir  = gameDir.resolve("libraries");
        Path   nativesDir    = versionDir.resolve("natives");

        List<Path> classpathEntries = new ArrayList<>(classpath);

        String cpStr = classpathEntries.stream()
                .map(p -> p.toAbsolutePath().toString())
                .collect(java.util.stream.Collectors.joining(File.pathSeparator));

        UUID resolvedUuid = offlineUUID(username);
        try {
            UUID premiumUuid = premiumUuidResolver.resolve(username);
            if (premiumUuid != null) {
                resolvedUuid = premiumUuid;
            }
        } catch (Exception ignored) {
            // No bloqueamos el lanzamiento si Mojang no responde.
        }

        Map<String, String> vars = new HashMap<>();
        vars.put("auth_player_name",    username);
        vars.put("version_name",        version);
        vars.put("game_directory",      gameDir.toAbsolutePath().toString());
        vars.put("assets_root",         assetsDir.toAbsolutePath().toString());
        vars.put("assets_index_name",   assetIndexId);
        vars.put("game_assets",         assetsDir.toAbsolutePath().toString());
        vars.put("auth_uuid",           resolvedUuid.toString());
        vars.put("auth_access_token",   "0");
        vars.put("auth_session",        "0");
        vars.put("clientid",            "0");
        vars.put("auth_xuid",           "0");
        vars.put("user_type",           "offline");
        vars.put("user_properties",     "{}");
        vars.put("profile_name",        username);
        vars.put("version_type",        meta.path("type").asText("release"));
        vars.put("launcher_name",       "FroshyLauncher");
        vars.put("launcher_version",    LauncherVersion.get());
        vars.put("natives_directory",   nativesDir.toAbsolutePath().toString());
        vars.put("library_directory",   librariesDir.toAbsolutePath().toString());
        vars.put("classpath_separator", File.pathSeparator);
        vars.put("classpath",           cpStr);
        vars.put("resolution_width",    "854");
        vars.put("resolution_height",   "480");

        // ── JVM arguments ────────────────────────────────────────────────
        List<String> jvmArgs = new ArrayList<>();
        JsonNode jvmArgsNode = meta.path("arguments").path("jvm");
        if (!jvmArgsNode.isMissingNode() && jvmArgsNode.isArray()) {
            jvmArgs.addAll(processArgNodes(jvmArgsNode, vars));
        } else {
            // Formato antiguo (<1.13): argumentos mínimos
            jvmArgs.add("-Djava.library.path=" + nativesDir.toAbsolutePath());
            jvmArgs.add("-Dminecraft.launcher.brand=FroshyLauncher");
            jvmArgs.add("-Dminecraft.launcher.version=1.0");
            jvmArgs.add("-cp");
            jvmArgs.add(cpStr);
        }

        // ── Game arguments ───────────────────────────────────────────────
        List<String> gameArgs = new ArrayList<>();
        JsonNode gameArgsNode = meta.path("arguments").path("game");
        if (!gameArgsNode.isMissingNode() && gameArgsNode.isArray()) {
            gameArgs.addAll(processArgNodes(gameArgsNode, vars));
        } else if (meta.has("minecraftArguments")) {
            for (String tok : meta.path("minecraftArguments").asText().split(" ")) {
                if (!tok.isBlank()) gameArgs.add(substitute(tok, vars));
            }
        }

        return new VersionInstallation(classpathEntries, mainClass, jvmArgs, gameArgs, nativesDir);
    }

    private boolean shouldIncludeClientJar(JsonNode meta, Path gameDir) {
        return !usesLibraryManagedMinecraftClient(meta, gameDir);
    }

    private boolean usesLibraryManagedMinecraftClient(JsonNode meta, Path gameDir) {
        if (!"cpw.mods.bootstraplauncher.BootstrapLauncher".equals(meta.path("mainClass").asText(""))) {
            return false;
        }

        JsonNode jvmArgs = meta.path("arguments").path("jvm");
        boolean forgeLikeBootstrap = jvmArgs.isArray() && processArgNodes(jvmArgs, Map.of()).stream()
                .anyMatch(arg -> arg.startsWith("-DignoreList=") && arg.contains("client-extra"));
        if (!forgeLikeBootstrap) {
            return false;
        }

        Path minecraftClientLibs = gameDir.resolve("libraries").resolve("net").resolve("minecraft").resolve("client");
        if (!Files.isDirectory(minecraftClientLibs)) {
            return false;
        }

        try (java.util.stream.Stream<Path> walk = Files.walk(minecraftClientLibs, 3)) {
            return walk
                    .filter(Files::isRegularFile)
                    .map(path -> path.getFileName().toString())
                    .anyMatch(name -> name.endsWith("-srg.jar") || name.endsWith("-slim.jar") || name.endsWith("-extra.jar"));
        } catch (IOException ex) {
            return false;
        }
    }

    private ResolvedVersionData resolveVersionData(String version, Path gameDir, Set<String> visiting)
            throws IOException {
        if (!visiting.add(version)) {
            throw new IOException("Cadena de herencia circular detectada en version: " + version);
        }

        Path versionJson = gameDir.resolve("versions").resolve(version).resolve(version + ".json");
        if (!Files.exists(versionJson)) {
            throw new IOException("Version " + version + " no instalada. Falta: " + versionJson);
        }

        ObjectNode current = (ObjectNode) mapper.readTree(versionJson.toFile());
        String parentId = current.path("inheritsFrom").asText("");

        if (parentId.isBlank()) {
            visiting.remove(version);
            return new ResolvedVersionData(current, findClientJarVersion(version, gameDir, new HashSet<>()));
        }

        ResolvedVersionData parent = resolveVersionData(parentId, gameDir, visiting);
        ObjectNode merged = mergeVersionMeta((ObjectNode) parent.meta(), current);
        visiting.remove(version);
        return new ResolvedVersionData(merged, findClientJarVersion(version, gameDir, new HashSet<>()));
    }

    private String findClientJarVersion(String version, Path gameDir, Set<String> visiting) throws IOException {
        if (!visiting.add(version)) {
            throw new IOException("Cadena de herencia circular al resolver JAR cliente: " + version);
        }

        Path versionDir = gameDir.resolve("versions").resolve(version);
        Path jar = versionDir.resolve(version + ".jar");
        Path json = versionDir.resolve(version + ".json");
        if (!Files.exists(json)) {
            throw new IOException("Version " + version + " no instalada. Falta: " + json);
        }

        ObjectNode meta = (ObjectNode) mapper.readTree(json.toFile());
        if (Files.exists(jar) || meta.path("downloads").path("client").has("url")) {
            return version;
        }

        String parent = meta.path("inheritsFrom").asText("");
        if (parent.isBlank()) {
            return version;
        }

        return findClientJarVersion(parent, gameDir, visiting);
    }

    private ObjectNode mergeVersionMeta(ObjectNode parent, ObjectNode child) {
        ObjectNode merged = parent.deepCopy();

        child.fields().forEachRemaining(entry -> {
            String field = entry.getKey();
            if ("libraries".equals(field) || "arguments".equals(field)) {
                return;
            }
            merged.set(field, entry.getValue());
        });

        ArrayNode mergedLibraries = mapper.createArrayNode();
        JsonNode parentLibraries = parent.path("libraries");
        if (parentLibraries.isArray()) {
            parentLibraries.forEach(mergedLibraries::add);
        }
        JsonNode childLibraries = child.path("libraries");
        if (childLibraries.isArray()) {
            childLibraries.forEach(mergedLibraries::add);
        }
        merged.set("libraries", mergedLibraries);

        ObjectNode mergedArguments = mapper.createObjectNode();
        JsonNode parentArgs = parent.path("arguments");
        JsonNode childArgs = child.path("arguments");
        mergeArgumentArray(parentArgs, childArgs, mergedArguments, "jvm");
        mergeArgumentArray(parentArgs, childArgs, mergedArguments, "game");
        if (!mergedArguments.isEmpty()) {
            merged.set("arguments", mergedArguments);
        }

        return merged;
    }

    private void mergeArgumentArray(JsonNode parentArgs, JsonNode childArgs, ObjectNode mergedArguments, String key) {
        ArrayNode merged = mapper.createArrayNode();

        if (parentArgs.isObject() && parentArgs.path(key).isArray()) {
            parentArgs.path(key).forEach(merged::add);
        }
        if (childArgs.isObject() && childArgs.path(key).isArray()) {
            childArgs.path(key).forEach(merged::add);
        }

        if (!merged.isEmpty()) {
            mergedArguments.set(key, merged);
        }
    }

    private record ResolvedVersionData(JsonNode meta, String clientJarVersion) {}


    // ═══════════════════════════════════════════════════════════════════════
    //  Helpers de argumentos
    // ═══════════════════════════════════════════════════════════════════════

    private List<String> processArgNodes(JsonNode nodes, Map<String, String> vars) {
        List<String> result = new ArrayList<>();
        for (JsonNode node : nodes) {
            if (node.isTextual()) {
                result.add(substitute(node.asText(), vars));
            } else if (node.isObject()) {
                JsonNode rules = node.path("rules");
                // Ignorar nodos con "features" (demo, custom resolution) excepto si los soportamos
                if (!node.path("rules").isMissingNode()
                        && node.path("rules").toString().contains("features")) {
                    continue;
                }
                if (evaluateRules(rules)) {
                    JsonNode val = node.path("value");
                    if (val.isTextual()) {
                        result.add(substitute(val.asText(), vars));
                    } else if (val.isArray()) {
                        val.forEach(v -> result.add(substitute(v.asText(), vars)));
                    }
                }
            }
        }
        return result;
    }

    private String substitute(String template, Map<String, String> vars) {
        String result = template;
        for (Map.Entry<String, String> e : vars.entrySet()) {
            result = result.replace("${" + e.getKey() + "}", e.getValue());
        }
        return result;
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  Helpers de reglas OS
    // ═══════════════════════════════════════════════════════════════════════

    private boolean evaluateRules(JsonNode rules) {
        if (rules == null || rules.isMissingNode() || rules.isEmpty()) return true;
        boolean allowed = false;
        for (JsonNode rule : rules) {
            String action = rule.path("action").asText("allow");
            boolean match = true;
            JsonNode os = rule.path("os");
            if (!os.isMissingNode()) {
                String reqOs = os.path("name").asText("");
                if (!reqOs.isEmpty() && !reqOs.equals(OS)) match = false;
            }
            // Ignorar reglas de "features" (se manejan por separado)
            if (!rule.path("features").isMissingNode()) match = false;
            if (match) allowed = "allow".equals(action);
        }
        return allowed;
    }

    private String getNativeClassifier(JsonNode lib) {
        JsonNode natives = lib.path("natives");
        if (natives.isMissingNode()) return null;
        JsonNode cls = natives.path(OS);
        if (cls.isMissingNode()) return null;
        String arch = System.getProperty("os.arch", "").contains("64") ? "64" : "32";
        return cls.asText().replace("${arch}", arch);
    }

    private String findVersionUrl(JsonNode manifest, String version) throws IOException {
        for (JsonNode v : manifest.path("versions")) {
            if (version.equals(v.path("id").asText())) {
                return v.path("url").asText();
            }
        }
        throw new IOException("Version de Minecraft no encontrada en manifest: " + version);
    }

    // ═══════════════════════════════════════════════════════════════════════
    //  Helpers de descarga HTTP
    // ═══════════════════════════════════════════════════════════════════════

    private JsonNode getJson(URI uri) throws IOException, InterruptedException {
        HttpRequest req = HttpRequest.newBuilder(uri)
                .timeout(Duration.ofSeconds(30))
                .header("User-Agent", "FroshyLauncher/1.0")
                .GET().build();
        HttpResponse<String> res = http.send(req, HttpResponse.BodyHandlers.ofString());
        if (res.statusCode() >= 300)
            throw new IOException("HTTP " + res.statusCode() + " → " + uri);
        return mapper.readTree(res.body());
    }

    private void downloadWithProgress(URI uri, Path dest, java.util.function.IntConsumer progress,
            String expectedSha1, long expectedSize) throws IOException, InterruptedException {
        HttpRequest req = HttpRequest.newBuilder(uri)
                .timeout(Duration.ofMinutes(5))
                .header("User-Agent", "FroshyLauncher/1.0")
                .GET().build();
        HttpResponse<InputStream> res = http.send(req, HttpResponse.BodyHandlers.ofInputStream());
        if (res.statusCode() >= 300)
            throw new IOException("HTTP " + res.statusCode() + " → " + uri);

        long total = res.headers().firstValueAsLong("Content-Length").orElse(-1L);
        Path tmp   = dest.resolveSibling(dest.getFileName() + ".part");
        Files.createDirectories(dest.getParent());

        try (InputStream in  = res.body();
             OutputStream out = Files.newOutputStream(tmp,
                     StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING)) {
            byte[] buf = new byte[16384];
            long read = 0; int n;
            while ((n = in.read(buf)) != -1) {
                out.write(buf, 0, n);
                read += n;
                if (total > 0) progress.accept((int)(read * 100 / total));
            }
        }
        verifyDownloadedFile(tmp, expectedSha1, expectedSize, uri);
        Files.move(tmp, dest, StandardCopyOption.REPLACE_EXISTING);
    }

    private void downloadSimple(URI uri, Path dest, String expectedSha1, long expectedSize)
            throws IOException, InterruptedException {
        Path tmp = dest.resolveSibling(dest.getFileName() + ".part");
        HttpRequest req = HttpRequest.newBuilder(uri)
                .timeout(Duration.ofMinutes(2))
                .header("User-Agent", "FroshyLauncher/1.0")
                .GET().build();
        HttpResponse<Path> res = http.send(req,
                HttpResponse.BodyHandlers.ofFile(tmp,
                        StandardOpenOption.CREATE,
                        StandardOpenOption.WRITE,
                        StandardOpenOption.TRUNCATE_EXISTING));
        if (res.statusCode() >= 300) {
            Files.deleteIfExists(tmp);
            throw new IOException("HTTP " + res.statusCode() + " → " + uri);
        }
        verifyDownloadedFile(tmp, expectedSha1, expectedSize, uri);
        Files.move(tmp, dest, StandardCopyOption.REPLACE_EXISTING);
    }

    private void verifyDownloadedFile(Path file, String expectedSha1, long expectedSize, URI uri) throws IOException {
        if (expectedSize > 0 && Files.size(file) != expectedSize) {
            throw new IOException("Tamano invalido para " + uri + " (esperado=" + expectedSize
                    + ", real=" + Files.size(file) + ")");
        }
        if (expectedSha1 != null && !expectedSha1.isBlank()) {
            String actual = sha1Hex(file);
            if (!expectedSha1.equalsIgnoreCase(actual)) {
                throw new IOException("SHA1 invalido para " + uri + " (esperado=" + expectedSha1
                        + ", real=" + actual + ")");
            }
        }
    }

    private void downloadTasks(List<DownloadTask> tasks, int threads,
            BiConsumer<Integer, Integer> onProgress) throws IOException, InterruptedException {
        if (tasks.isEmpty()) return;

        ExecutorService pool = Executors.newFixedThreadPool(Math.max(1, threads));
        CompletionService<Void> completion = new ExecutorCompletionService<>(pool);
        ConcurrentLinkedQueue<String> failures = new ConcurrentLinkedQueue<>();

        for (DownloadTask task : tasks) {
            completion.submit(() -> {
                Files.createDirectories(task.dest().getParent());
                withRetryVoid(task.id(), () -> downloadSimple(task.uri(), task.dest(), task.sha1(), task.size()));
                return null;
            });
        }

        try {
            for (int i = 1; i <= tasks.size(); i++) {
                try {
                    completion.take().get();
                } catch (ExecutionException ex) {
                    Throwable cause = ex.getCause() != null ? ex.getCause() : ex;
                    failures.add(cause.getMessage());
                }
                onProgress.accept(i, tasks.size());
            }
        } finally {
            pool.shutdown();
            if (!pool.awaitTermination(60, TimeUnit.MINUTES)) {
                pool.shutdownNow();
            }
        }

        if (!failures.isEmpty()) {
            String detail = failures.stream().limit(3).collect(java.util.stream.Collectors.joining(" | "));
            throw new IOException("Descargas incompletas (" + failures.size() + " fallos): " + detail);
        }
    }

    // ── Extracción de nativos ────────────────────────────────────────────

    private void extractNatives(Path nativeJar, Path nativesDir) throws IOException {
        Files.createDirectories(nativesDir);
        try (ZipInputStream zip = new ZipInputStream(Files.newInputStream(nativeJar))) {
            ZipEntry entry;
            while ((entry = zip.getNextEntry()) != null) {
                String name = entry.getName();
                if (name.startsWith("META-INF/")) { zip.closeEntry(); continue; }
                if (name.endsWith(".dll") || name.endsWith(".so")
                        || name.endsWith(".dylib") || name.endsWith(".jnilib")) {
                    Path target = nativesDir.resolve(Path.of(name).getFileName());
                    if (!Files.exists(target)) {
                        Files.copy(zip, target, StandardCopyOption.REPLACE_EXISTING);
                    }
                }
                zip.closeEntry();
            }
        }
    }

    // ── Utilidades ───────────────────────────────────────────────────────

    private boolean isValidFile(Path p, long minSize) {
        try { return Files.exists(p) && Files.size(p) >= minSize; }
        catch (IOException e) { return false; }
    }

    private boolean isValidFile(Path p, long minSize, String expectedSha1) {
        try {
            if (!Files.exists(p) || Files.size(p) < minSize) return false;
            if (expectedSha1 == null || expectedSha1.isBlank()) return true;
            return expectedSha1.equalsIgnoreCase(sha1Hex(p));
        } catch (IOException e) {
            return false;
        }
    }

    private String textOrNull(JsonNode node) {
        if (node == null || node.isMissingNode()) return null;
        String value = node.asText("").trim();
        return value.isEmpty() ? null : value;
    }

    private String sha1Hex(Path file) throws IOException {
        MessageDigest md;
        try {
            md = MessageDigest.getInstance("SHA-1");
        } catch (NoSuchAlgorithmException ex) {
            throw new IllegalStateException("SHA-1 no disponible", ex);
        }

        try (InputStream in = Files.newInputStream(file)) {
            byte[] buf = new byte[16_384];
            int n;
            while ((n = in.read(buf)) != -1) {
                md.update(buf, 0, n);
            }
        }
        return toHex(md.digest());
    }

    private String toHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder(bytes.length * 2);
        for (byte b : bytes) {
            sb.append(Character.forDigit((b >>> 4) & 0xF, 16));
            sb.append(Character.forDigit(b & 0xF, 16));
        }
        return sb.toString();
    }

    private static UUID offlineUUID(String username) {
        return UUID.nameUUIDFromBytes(
                ("OfflinePlayer:" + username).getBytes(StandardCharsets.UTF_8));
    }

    private UUID resolvePremiumUuidFromMojang(String username) throws IOException, InterruptedException {
        if (username == null || !username.matches("^[A-Za-z0-9_]{3,16}$")) {
            return null;
        }

        String encodedUser = URLEncoder.encode(username, StandardCharsets.UTF_8);
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(MOJANG_PROFILE_API + encodedUser))
                .timeout(Duration.ofSeconds(4))
                .header("Accept", "application/json")
                .GET()
                .build();

        HttpResponse<String> response = http.send(request, HttpResponse.BodyHandlers.ofString());
        if (response.statusCode() != 200 || response.body() == null || response.body().isBlank()) {
            return null;
        }

        JsonNode payload = mapper.readTree(response.body());
        String rawId = payload.path("id").asText("").trim();
        if (!rawId.matches("^[0-9a-fA-F]{32}$")) {
            return null;
        }

        String hyphenated = rawId.substring(0, 8) + "-"
                + rawId.substring(8, 12) + "-"
                + rawId.substring(12, 16) + "-"
                + rawId.substring(16, 20) + "-"
                + rawId.substring(20);
        return UUID.fromString(hyphenated);
    }

    @FunctionalInterface
    interface PremiumUuidResolver {
        UUID resolve(String username) throws IOException, InterruptedException;
    }

    // ── Retry helpers ────────────────────────────────────────────────────

    private <T> T withRetry(String op, ThrowingSupplier<T> s) throws IOException, InterruptedException {
        IOException last = null;
        for (int i = 1; i <= MAX_RETRIES; i++) {
            try { return s.get(); }
            catch (IOException ex) {
                last = ex;
                if (i < MAX_RETRIES) Thread.sleep(500L * i);
            }
        }
        throw new IOException("Falló " + op + " tras " + MAX_RETRIES + " intentos", last);
    }

    private void withRetryVoid(String op, ThrowingRunnable r) throws IOException, InterruptedException {
        withRetry(op, () -> { r.run(); return null; });
    }

    @FunctionalInterface private interface ThrowingSupplier<T> {
        T get() throws IOException, InterruptedException;
    }
    @FunctionalInterface private interface ThrowingRunnable {
        void run() throws IOException, InterruptedException;
    }
}

package am.froshy.launcher.ui;
import am.froshy.launcher.api.internal.InternalApiClient;
import am.froshy.launcher.domain.LaunchRequest;
