        if (selected == null) return;
        runAsync(() -> {
            String applied = apiClient.setModpackCompatibilityMode(selected.toString());
            SwingUtilities.invokeLater(() -> {
                suppressComboEvents = true;
                modpackCompatField.setSelectedItem(applied);
